insert into aura_exercise_catalog (id, payload, updated_at) values
  ('EB5CD667-3654-5944-86B0-292B3A367872'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"EB5CD667-3654-5944-86B0-292B3A367872","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"EZ Bar Standing French Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the ez barbell with an overhand grip.","Raise the barbell above your head, fully extending your arms.","Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"B51FBE3F-D66B-5505-96D6-D22BA9B7D901","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"9E2057AA-0749-5B2D-8830-4A4A27C6F4AF","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"FCFDB4A0-F7A4-5E07-8E29-EC31E4A4A545","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E810A656-0987-56FD-9E2D-42755C89D6B5","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('210C4CBE-F888-5818-869A-D25416B71608'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"210C4CBE-F888-5818-869A-D25416B71608","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Chest"],"name":"EZ Barbell Anti Gravity Press","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and holding the ez barbell with an overhand grip.","Raise the barbell to shoulder height, keeping your elbows slightly bent and your palms facing forward.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7107BFB8-01BE-5AC4-A084-EBB7A89453E0","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"98843003-68D5-5FA5-AF72-6B4E34F32AF0","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"88BBD728-CB2C-5145-858D-3AFD25695769","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"C8B705EC-3318-5112-8358-CC45C271DBEA","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A8E747CF-FC9E-53FF-A63D-DBC26215E5A5'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"A8E747CF-FC9E-53FF-A63D-DBC26215E5A5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ Barbell Close Grip Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher curl bench and place your upper arms on the pad, gripping the ez barbell with an underhand grip.","Rest your triceps on the pad and fully extend your arms, keeping your back straight.","Slowly curl the barbell towards your shoulders, contracting your biceps.","Pause for a moment at the top, squeezing your biceps.","Lower the barbell back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"F041B82F-1247-5C9E-8514-2CF0BC159E51","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"10D302C0-37DB-575A-ACCF-21AC5EB854C7","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"C2DC6901-B9B4-57E3-8279-CC74A61C9257","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"601FE021-4B57-59B5-AA06-982D1FE2164F","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('83D9B422-49FF-5B4D-AA57-CC0BF89E5037'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"83D9B422-49FF-5B4D-AA57-CC0BF89E5037","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ Barbell Close-Grip Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Curl the barbell up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"11E8D23B-71FD-5DAE-8D8F-1AA401FF227C","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"92897EAA-6C1C-5AC1-9368-6144D985BCE1","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"922F8049-D614-564B-87D6-0A56F9D8AD7E","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D5239084-3006-5BF1-9626-ED3DD47F2119","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7943F52A-E5F6-5F05-B5BE-87663EC50F44'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"7943F52A-E5F6-5F05-B5BE-87663EC50F44","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ Barbell Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Exhale as you curl the barbell up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1A4DA830-0487-5FE0-8493-20C3461569C3","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2FE7A249-ECA6-5BEB-BB90-4A0D815B4539","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5BF2E9D1-CD3D-5E2E-9FED-3C8C48B31638","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"CA8B65A9-6625-5C9D-A034-896BB6185C3E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2AE0547A-AE8D-54C5-B8B8-38EEFDEB37DF'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"2AE0547A-AE8D-54C5-B8B8-38EEFDEB37DF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"EZ Barbell Decline Close Grip Face Press","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your head lower than your feet.","Grasp the ez barbell with a close grip, palms facing each other.","Extend your arms straight up above your chest, keeping your elbows close to your body.","Lower the barbell towards your forehead by bending your elbows.","Pause for a moment, then press the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"3F67BAA7-DFD1-5F70-9164-24333B1A364F","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"ACF97A1B-17B5-5F3F-B7CA-558C3E4E3544","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"109E20F1-4D1E-5A3C-9330-7406C6DAF1AA","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"76D84D60-8754-5C3D-A963-9C6BA05244DC","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4771F4E9-FEEA-563A-822F-5D13098A49F7'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"4771F4E9-FEEA-563A-822F-5D13098A49F7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"EZ Barbell Decline Triceps Extension","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your head lower than your feet and your feet secured.","Hold the ez barbell with an overhand grip, hands shoulder-width apart.","Extend your arms fully, keeping your elbows close to your head.","Lower the barbell slowly towards your forehead, bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"109462DB-AF0D-55FD-9DA3-14C52AE45C89","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E51CC5DD-51D2-5D19-B79B-F64F91055136","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"3BAAEFC1-05D4-5881-8135-45CFC0AB00F3","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"94F85FAF-BF60-598C-B3E8-60A624172748","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B3C5434F-C3A8-518E-A261-9C03B37D4BE7'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"B3C5434F-C3A8-518E-A261-9C03B37D4BE7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"EZ Barbell Incline Triceps Extension","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and hold the ez barbell with an overhand grip.","Extend your arms fully overhead, keeping your elbows close to your head.","Lower the barbell behind your head by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E28F04E7-57BC-548D-BC5E-39CE54414683","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"73A8E963-B321-5D15-843D-F4010D8F2690","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5E34557A-E715-5A59-B9BB-DB9CD95B76B9","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"CAAC5DFD-3135-530C-98DC-8066B9E88E9E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F9B1520F-9DCE-56D1-881E-807193A79DBC'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"F9B1520F-9DCE-56D1-881E-807193A79DBC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"EZ Barbell Jm Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the ez barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows tucked in close to your body.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"837043C2-823E-5623-B91E-1562A126C995","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0E6326A0-EA9C-5D47-BE68-AACA2E9D23C5","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"01235EBA-100D-56B9-AD6A-FC47449C9378","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3DEA091A-0FBB-5BB0-9854-C8DC28154A63","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('52C013F3-760A-576B-9F01-7A46E51B6F82'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"52C013F3-760A-576B-9F01-7A46E51B6F82","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ Barbell Reverse Grip Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip.","Keep your elbows close to your torso and your upper arms stationary throughout the exercise.","Curl the barbell upwards by contracting your biceps, while exhaling.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Slowly begin to bring the barbell back to the starting position as you inhale.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"8055D225-3183-5146-BBD3-7093C6D259AB","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"A241FA23-6BD4-5E9A-A041-C4033A39F555","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"37116F26-12DB-55EE-AAA3-32B146ACEE86","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3231B08B-F714-534B-8B1B-1BC33989F594","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BB431118-47C2-5850-BBCC-E872409F3F29'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"BB431118-47C2-5850-BBCC-E872409F3F29","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ Barbell Reverse Grip Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with your chest against the pad and your feet flat on the floor.","Grasp the ez barbell with an underhand grip, hands shoulder-width apart.","Rest your upper arms on the pad, allowing your forearms to hang down.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"B70971C0-1AD5-5743-9B35-FAC7E847BF05","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"54644253-74DB-53E7-9F7E-95F9BC17BC8A","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7AF06E4B-845E-5EE9-9EA0-1092D67148E8","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"F7C31D89-0055-57DE-AAB3-DCF3D446E318","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2D7DA883-F542-54E8-B902-A061F5AB68F2'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"2D7DA883-F542-54E8-B902-A061F5AB68F2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ Barbell Seated Curls","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and your back straight.","Hold the ez barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.","Rest your upper arms on your thighs, allowing the ez barbell to hang down in front of you.","Keeping your upper arms stationary, exhale and curl the ez barbell upwards towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the ez barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7CCDB993-2EEC-5635-BBB1-8C5E7872BD73","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"240D3546-26B0-500C-BA20-50B2FC33838E","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"6CB208EF-6862-5D24-9A96-A56E315B72BE","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E5C1D8E1-FE2C-5E48-AEB5-A1D12C6D14FA","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E6669512-9328-530B-AC77-CE0F871EB2D3'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E6669512-9328-530B-AC77-CE0F871EB2D3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"EZ Barbell Seated Triceps Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold the ez barbell with an overhand grip, hands shoulder-width apart.","Raise the barbell overhead, fully extending your arms.","Keeping your upper arms stationary, lower the barbell behind your head by bending your elbows.","Pause for a moment, then raise the barbell back to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"DD9F2A90-2DD6-5D6B-AA9C-0514AF850FF3","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"95CCD880-9E41-59FE-9392-E9EBC835A8E6","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"4DBCBEB6-14C0-5609-96AE-86E20E578596","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"C760AE64-C295-5321-A7D8-DF7074F9973A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F7945E5B-57B9-58A5-98A4-4FF22F67A2F0'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"F7945E5B-57B9-58A5-98A4-4FF22F67A2F0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ Barbell Spider Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up.","Rest your upper arms on a preacher bench or stability ball, allowing your elbows to hang down.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"6F4A7DD7-7464-5224-962D-27E0B8F0C977","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"1DA62B21-2C18-5868-A92C-406628EF5625","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"6130E171-F201-57BC-8B9C-A0DBB15AE106","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"1DF28B78-7DE3-56C9-8B35-FEAC2E1E265E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2A49DE54-1BCA-55E8-8D26-B4D5443C0638'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"2A49DE54-1BCA-55E8-8D26-B4D5443C0638","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ-Bar Biceps Curl (With Arm Blaster)","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up.","Place your upper arms against the arm blaster, keeping them stationary throughout the exercise.","Keeping your elbows close to your body, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"D470E58B-F8CE-5799-A1D5-4E42279774BB","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"279109F9-A5F1-5FBE-B072-8C49921BE978","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"E2A7C35C-AAFA-5FFA-A34F-D72447B8D9E1","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"224B458F-A6FD-5174-BFB5-74C357258B9F","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('81D53025-104B-5FE7-8118-F6EAEE391BC9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"81D53025-104B-5FE7-8118-F6EAEE391BC9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"EZ-Bar Close-Grip Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the ez barbell with a close grip, hands shoulder-width apart, palms facing forward.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"9E91E739-08D8-52EA-967D-D952E6716E62","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"CC5E3C6F-5F23-5D3F-80F6-29EFA49ADDF6","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"1344E22C-DEF0-5B81-B63C-83B300EDAE2A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"44D9040D-960B-5AD3-A33C-F4E66FFDA8D7","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('67A15B8B-2F82-5BC3-A0E9-E960EC01883E'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"67A15B8B-2F82-5BC3-A0E9-E960EC01883E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ-Barbell Standing Wide Grip Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, hands wider than shoulder-width apart.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Curl the barbell up towards your shoulders by contracting your biceps.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A84D8A26-CE9A-5997-AF5B-DAE1621797E6","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"93CC6D78-7125-5189-84D3-CAD8CF780B8C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"744D488D-F14B-515F-AB2A-C9B738DCEF73","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D4397B1B-9BD7-52EF-B1DF-F39A2C73C931","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('111F7778-FA22-50B5-9770-6435C1442C5B'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"111F7778-FA22-50B5-9770-6435C1442C5B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Elbow Dips","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.","Slide your hips forward off the bench and straighten your legs, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"47667B91-A830-5E4D-83C5-ECFEA4708C97","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C04F7787-31CD-57AA-8CC8-C6CD801D7B3D'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C04F7787-31CD-57AA-8CC8-C6CD801D7B3D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Triceps","Shoulders"],"name":"Elbow Lift - Reverse Push-Up","notes":"","plannedSets":3,"proTips":["Start by lying face down on the ground with your legs extended and your hands placed directly under your shoulders.","Engage your core and press through your palms to lift your upper body off the ground, keeping your elbows close to your sides.","Pause at the top for a moment, squeezing your upper back muscles.","Slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9F4F97A5-9B8F-582D-ADBA-A23690560B72","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F553CCF6-7ED8-58F0-A5FB-96A39AB7E8C7'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"F553CCF6-7ED8-58F0-A5FB-96A39AB7E8C7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Elbow-To-Knee","notes":"","plannedSets":3,"proTips":["Start by lying flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee.","At the same time, bring your left knee towards your right elbow, creating a twisting motion.","Pause for a moment at the top, then slowly lower your upper body and extend your legs back to the starting position.","Repeat the movement, this time bringing your left elbow towards your right knee and your right knee towards your left elbow.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"767D99E9-B405-5799-A97C-F2BE68DB398D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AEF7322E-8040-551E-A3B8-769EE28C9F51'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"AEF7322E-8040-551E-A3B8-769EE28C9F51","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Shoulders","Trapezius"],"name":"Elevator","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Place your hands on your hips or cross them in front of your chest.","Keeping your back straight, slowly bend forward at the waist, lowering your upper body towards the ground.","Pause for a moment at the bottom, then slowly raise your upper body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"79A5DFE7-4D18-552D-9C77-2988040B3168","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D990BF96-FBCA-5019-83B2-8494254403A0'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"D990BF96-FBCA-5019-83B2-8494254403A0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Core"],"name":"Exercise Ball Alternating Arm Ups","notes":"","plannedSets":3,"proTips":["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing inwards and your arms extended down by your sides.","Engage your core and slowly lift one arm up towards your shoulder, keeping your elbow slightly bent.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat the movement with the other arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4B99D36B-1198-5F82-9E38-B3A507F84937","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2EF7588C-1087-5E1E-A867-55AD526CF082'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"2EF7588C-1087-5E1E-A867-55AD526CF082","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Exercise Ball Back Extension With Arms Extended","notes":"","plannedSets":3,"proTips":["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability.","Extend your arms straight out in front of you, with your palms facing down.","Engage your core and slowly lift your upper body off the ball, keeping your back straight and your neck in line with your spine.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9B31A7EE-7B9C-54DD-BA80-36CE3C219D09","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1252D30C-F0E3-5511-A028-329990EADD7F'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"1252D30C-F0E3-5511-A028-329990EADD7F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Exercise Ball Back Extension With Hands Behind Head","notes":"","plannedSets":3,"proTips":["Place the stability ball on the ground and lie face down on top of it with your hips resting on the ball.","Position your feet against a wall or other stable surface for support.","Cross your arms behind your head, with your hands touching the back of your head.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your hips.","Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A525C666-AB02-566B-AA04-B12369A58880","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F8B4FB0A-5BC0-5E56-9A7F-44F0F1AAC99D'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"F8B4FB0A-5BC0-5E56-9A7F-44F0F1AAC99D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Exercise Ball Back Extension With Knees Off Ground","notes":"","plannedSets":3,"proTips":["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability.","Position your hands behind your head or crossed over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0AC02404-D7FC-539A-999C-67A39B42308D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('75CB52D3-32E3-5DEE-BFBF-E62754FDE815'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"75CB52D3-32E3-5DEE-BFBF-E62754FDE815","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Exercise Ball Back Extension With Rotation","notes":"","plannedSets":3,"proTips":["Start by lying face down on the stability ball with your hips resting on the ball and your feet firmly planted on the ground.","Place your hands behind your head or cross them over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly rotate your torso to one side, keeping your hips and legs stable.","Return to the center and repeat the rotation to the other side.","Lower your upper body back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"AC81B16B-A782-55C5-AF90-A542AE0EA128","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('276BC9EB-3F61-5DE3-B30B-48C0CD35DD5F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"276BC9EB-3F61-5DE3-B30B-48C0CD35DD5F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Exercise Ball Dip","notes":"","plannedSets":3,"proTips":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Place your hands on the ball beside your hips, fingers pointing forward.","Engage your triceps and push through your hands to lift your body off the ball, straightening your arms.","Lower your body back down by bending your elbows, keeping them close to your sides.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C9809E43-D68A-5012-84A0-B340AC5BE237","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('541C3FAE-312E-5626-BDEF-2A98B9683D11'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"541C3FAE-312E-5626-BDEF-2A98B9683D11","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings"],"name":"Exercise Ball Hip Flexor Stretch","notes":"","plannedSets":3,"proTips":["Place the stability ball on the ground and kneel in front of it.","Place your right foot on top of the stability ball, with your knee bent at a 90-degree angle.","Extend your left leg behind you, keeping it straight.","Lean forward, pushing your hips towards the stability ball, until you feel a stretch in your right hip flexor.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"18E3111A-64B8-590B-B6EB-8DE01F793A6A","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('065B6478-C95A-548F-BF04-6894DF005E64'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"065B6478-C95A-548F-BF04-6894DF005E64","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Shoulders","Chest"],"name":"Exercise Ball Hug","notes":"","plannedSets":3,"proTips":["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold the stability ball with both hands, hugging it close to your chest.","Engage your core muscles and slowly lean back, keeping your back straight and your feet planted on the ground.","Continue leaning back until you feel a stretch in your back muscles.","Hold the position for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5D5364B8-DEDF-51CD-B97B-E68227227AB8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F86CA4EB-141B-55E2-99F5-E186AF3EEEBC'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"F86CA4EB-141B-55E2-99F5-E186AF3EEEBC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Triceps"],"name":"Exercise Ball Lat Stretch","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand and extend your arm straight up overhead.","Slowly lean to the opposite side, feeling a stretch in your lat muscle.","Hold the stretch for 20-30 seconds, then return to the starting position.","Repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"EFD544D3-FE07-56DF-8A34-635F9652542B","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('047F8F2B-66D6-5179-9BBC-978126F15634'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"047F8F2B-66D6-5179-9BBC-978126F15634","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Glutes","Hamstrings"],"name":"Exercise Ball Lower Back Stretch (Pyramid)","notes":"","plannedSets":3,"proTips":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Slowly walk your feet forward, rolling the ball down your back until your lower back is resting on the ball.","Place your hands behind your head or cross them over your chest.","Engage your core and slowly lower your upper body towards the ground, allowing your lower back to stretch over the ball.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"E95E2A01-8DEF-5CAD-8695-39C4959BEACF","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('8AAB6DF2-6DD9-54DB-9231-DFF57722DF18'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"8AAB6DF2-6DD9-54DB-9231-DFF57722DF18","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Triceps"],"name":"Exercise Ball Lying Side Lat Stretch","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs extended and your head supported by the stability ball.","Place your top arm on the ball for stability.","Reach your top arm overhead and allow your torso to rotate slightly.","Feel the stretch in your lat muscles on the side of your body.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"D9D473C6-C9F7-5132-AD55-49FB5CBE4E97","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('B26D0526-7346-5ED5-9907-DCF1688F7E4E'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B26D0526-7346-5ED5-9907-DCF1688F7E4E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Quadriceps"],"name":"Exercise Ball On The Wall Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your back against a wall and place an exercise ball between your lower back and the wall.","Position your feet shoulder-width apart, with your toes pointing forward.","Hold a dumbbell in each hand, with your arms extended by your sides.","Raise your heels off the ground, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CE8D565C-5543-5E08-B85A-41A232632A9B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B9896096-AF5A-53D1-9144-9D1EBD14B288'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B9896096-AF5A-53D1-9144-9D1EBD14B288","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Quadriceps"],"name":"Exercise Ball On The Wall Calf Raise (Tennis Ball Between Ankles)","notes":"","plannedSets":3,"proTips":["Stand facing a wall with your feet shoulder-width apart.","Place an exercise ball between the wall and your lower back.","Hold a dumbbell in each hand, with your arms extended by your sides.","Place a tennis ball between your ankles.","Raise your heels off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"50485B5F-8593-576B-97DF-4C0EE23E10DD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7F961122-6EFE-5AFB-BA7F-ECD5D065018E'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7F961122-6EFE-5AFB-BA7F-ECD5D065018E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Quadriceps","Hamstrings"],"name":"Exercise Ball On The Wall Calf Raise (Tennis Ball Between Knees)","notes":"","plannedSets":3,"proTips":["Stand with your back against a wall and place an exercise ball between your lower back and the wall.","Position your feet shoulder-width apart and slightly in front of you.","Hold a dumbbell in each hand, with your arms extended by your sides.","Place a tennis ball between your knees.","Raise your heels off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4B9983FE-3DF3-5458-B979-A0C52B71040C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FE740F1F-9A7D-568A-AD8B-0BCC86BE0FDC'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"FE740F1F-9A7D-568A-AD8B-0BCC86BE0FDC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Core"],"name":"Exercise Ball One Leg Prone Lower Body Rotation","notes":"","plannedSets":3,"proTips":["Lie face down on the stability ball with your hips resting on the ball and your legs extended straight behind you.","Place your hands on the ground in front of you for support.","Engage your glutes and core muscles to stabilize your body.","Slowly lift one leg off the ground, keeping it straight and parallel to the floor.","Rotate your leg outward, away from your body, while keeping your hips and upper body stable.","Pause for a moment at the end of the rotation, then slowly return your leg to the starting position.","Repeat the rotation with the other leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"B92B04F9-93AD-5087-9D4E-D241EBFC8F8D","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('CFA832DC-A146-5ED3-A033-564EB8826F6F'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"CFA832DC-A146-5ED3-A033-564EB8826F6F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Calves"],"name":"Exercise Ball One Legged Diagonal Kick Hamstring Curl","notes":"","plannedSets":3,"proTips":["Start by lying on your back with your legs extended and your heels resting on top of the stability ball.","Place your arms by your sides for stability.","Engage your glutes and core muscles to lift your hips off the ground, creating a straight line from your shoulders to your heels.","Bend your right knee and bring it towards your chest, keeping your left leg extended and your foot flexed.","Kick your right leg diagonally across your body, extending it fully and engaging your hamstrings.","Slowly return your right leg to the starting position, maintaining control and stability.","Repeat the movement with your left leg, alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"987BDEA7-8CCB-5F6C-A91C-802E3F912533","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E36CC984-752D-509F-9B47-7B735698064B'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"E36CC984-752D-509F-9B47-7B735698064B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps","Core"],"name":"Exercise Ball Pike Push Up","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands on the floor and your shins resting on the stability ball.","Engage your core and lift your hips up towards the ceiling, rolling the ball towards your hands.","Keep your legs straight and your body in a pike position, forming an inverted V shape.","Bend your elbows and lower your upper body towards the floor, keeping your head in line with your hands.","Push through your hands and extend your arms to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"68CA4B37-F857-5BB2-B907-D33077D6B070","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('38CDF097-8477-56E1-87CC-9DB0549AFBFC'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"38CDF097-8477-56E1-87CC-9DB0549AFBFC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Abdominals","Glutes"],"name":"Exercise Ball Prone Leg Raise","notes":"","plannedSets":3,"proTips":["Lie face down on a mat with your legs extended and your toes resting on top of the stability ball.","Place your hands on the ground, shoulder-width apart, and engage your core muscles.","Keeping your legs straight, slowly lift them off the ground, using your lower back and glutes to raise them as high as possible.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"89B93902-8B63-5352-92D5-7EBD676C8F27","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1AEF9C40-DA0F-50B8-8A94-A2274CDFF0D3'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"1AEF9C40-DA0F-50B8-8A94-A2274CDFF0D3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Lower Back"],"name":"Exercise Ball Seated Hamstring Stretch","notes":"","plannedSets":3,"proTips":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Slowly roll the ball forward, walking your feet out until your upper back is resting on the ball and your legs are extended straight in front of you.","Place your hands on your hips for support.","Engage your core and slowly lower your upper body towards the ground, keeping your back straight and your chest lifted.","Stop when you feel a stretch in your hamstrings, and hold the position for 20-30 seconds.","Slowly return to the starting position by pushing through your heels and using your hamstrings to pull yourself back up.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"6267B86E-D86D-5B9C-A7B4-328B47D5213D","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('8DC57C3D-FA4B-5E89-A05B-0A400A2997D9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"8DC57C3D-FA4B-5E89-A05B-0A400A2997D9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Exercise Ball Seated Triceps Stretch","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand and extend your arm straight up above your head.","Bend your elbow and lower the dumbbell behind your head, keeping your upper arm close to your ear.","Hold the stretch for a few seconds, then return to the starting position.","Repeat with the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"524DEF7E-23EE-5ABD-A888-7737CD5F23B9","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('96C7B32A-DCD0-5119-A4E8-8754585008EE'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"96C7B32A-DCD0-5119-A4E8-8754585008EE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Exercise Ball Supine Triceps Extension","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell with both hands and extend your arms straight up towards the ceiling.","Slowly lower the dumbbell behind your head, keeping your elbows close to your ears.","Pause for a moment, then raise the dumbbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0FBB5EC2-A019-59AD-8F90-1FA258C69F6F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2F7729C2-D343-5054-883A-14EAF05E2629'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2F7729C2-D343-5054-883A-14EAF05E2629","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Calves","Forearms","Core"],"name":"Farmers Walk","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your sides.","Keep your back straight and your shoulders back.","Take small, controlled steps forward, maintaining an upright posture.","Continue walking for the desired distance or time.","To finish, stop walking and carefully lower the dumbbells to your sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"722E6818-77ED-5F83-9463-386CEC241AF2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C4E04263-8390-5AD8-88D4-7D0B5D86A347'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"C4E04263-8390-5AD8-88D4-7D0B5D86A347","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Wrist Flexors","Grip Muscles"],"name":"Finger Curls","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your fingers towards your palms, squeezing the barbell tightly.","Hold the contraction for a moment, then slowly release your fingers back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"319586DA-6EB5-5579-B9BF-890B1BBB568E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"5DF0D471-0494-5D92-A454-33DA4EF82153","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"71B584C4-3036-5460-9C61-FF73B9799FDB","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4EA88A4F-2B54-567B-B380-3C9A2B166AF1","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1D113653-562F-539D-9EF6-0607D66873B2'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1D113653-562F-539D-9EF6-0607D66873B2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Shoulders"],"name":"Flag","notes":"","plannedSets":3,"proTips":["Start by gripping a vertical pole with both hands, palms facing each other, and arms fully extended.","Engage your core and lift your legs off the ground, keeping them straight.","Using your core and upper body strength, raise your legs until they are parallel to the ground.","Hold this position for as long as you can, maintaining a straight body line.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1723CFD1-EFFA-5535-98BC-2FA5DD18DE13","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DA89DF52-B803-52F6-BF21-829EEACA4454'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DA89DF52-B803-52F6-BF21-829EEACA4454","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Flexion Leg Sit Up (Bent Knee)","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","At the same time, lift your legs off the ground, bending your knees and bringing them towards your chest.","Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"28635E29-218D-573B-97FC-1AF4F52676F8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C29248D0-E763-5F28-9B68-D5A38041467B'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C29248D0-E763-5F28-9B68-D5A38041467B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Quadriceps"],"name":"Flexion Leg Sit Up (Straight Arm)","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and arms straight above your head.","Engaging your abs, lift your upper body off the ground while simultaneously lifting your legs towards your chest.","Reach your hands towards your toes as you lift your upper body and legs.","Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C8A6581B-B6ED-5313-ADAD-CA0F9084EECF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('34BD31C9-D4F4-5B92-A586-80B0553477B9'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"34BD31C9-D4F4-5B92-A586-80B0553477B9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Floor Fly (With Barbell)","notes":"","plannedSets":3,"proTips":["Lie flat on your back on the floor with your knees bent and feet flat on the ground.","Hold a barbell with an overhand grip, arms extended straight up over your chest.","Slowly lower the barbell out to the sides, keeping a slight bend in your elbows.","Lower the barbell until your arms are parallel to the floor, feeling a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7B2A4749-33D4-5EBB-8B5D-CE35AC688AB0","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"827ADD2E-1B2A-5DB1-89D1-337D76DE13DC","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B1508D72-D613-5773-B182-8BD8C6C9CAAC","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"A13F5B14-BAE4-5390-A91A-9E973A13DA2A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C77CED34-15E6-5512-B123-76D967FF7D3C'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C77CED34-15E6-5512-B123-76D967FF7D3C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hip Flexors","Lower Abs"],"name":"Flutter Kicks","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and your hands by your sides.","Engage your core and lift your legs off the ground about 6 inches.","Keeping your legs straight, alternate lifting one leg slightly higher than the other.","Continue this fluttering motion for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"13CE5357-ECC3-5504-9B99-AB9A3D752396","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('964E299B-7306-5083-ABC8-E8A0B537628F'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"964E299B-7306-5083-ABC8-E8A0B537628F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Calves","Hamstrings","Glutes"],"name":"Forward Jump","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Swing your arms back for momentum.","Jump forward explosively, extending your hips, knees, and ankles.","Land softly on the balls of your feet and immediately go into the next jump.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"ABD5C816-57D2-5C27-9CEE-657C995F02CB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F157DBCD-90DD-5776-95B2-863D4F61F9F0'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"F157DBCD-90DD-5776-95B2-863D4F61F9F0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Forward Lunge","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart and hands on your hips.","Take a big step forward with your right foot, lowering your body into a lunge position.","Bend your right knee to about 90 degrees, keeping your knee aligned with your ankle.","Push off with your right foot and return to the starting position.","Repeat with your left leg, alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"26731C5E-AD00-500B-90E3-444937F4F062","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BA70DCBE-D813-5BB3-A59B-7D34B6D6568B'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"BA70DCBE-D813-5BB3-A59B-7D34B6D6568B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Frankenstein Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the barbell in front of your body with straight arms.","Keeping your back straight, lower your body by bending at the knees and hips, as if sitting back into a chair.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"641EBA94-1F0A-5A44-BAD7-945903BDFF92","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"1839ED53-3D93-57C1-B497-F670D5B197DE","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"9162B7CF-EC55-5265-A342-56A4573D7CD3","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"907848BE-8478-525E-B5E5-34FAA867C57E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('68BBF998-6EA1-501C-B824-A38BCC75C53C'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"68BBF998-6EA1-501C-B824-A38BCC75C53C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Frog Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2C3F7B80-C248-51D1-B5D9-3D3DC85635F1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A28176D0-D333-57CF-B772-BEB5F65E6ECA'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A28176D0-D333-57CF-B772-BEB5F65E6ECA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Chest","Triceps"],"name":"Frog Planche","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands shoulder-width apart and your feet together.","Bend your elbows and lower your body towards the ground, keeping your back straight.","As you lower your body, lift your feet off the ground and bring your knees towards your chest.","Hold this position for a few seconds, then extend your legs back out and push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F73ACDE6-551E-511C-89D0-5FD302F70B58","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('298F55BC-0709-57F3-9D03-8449D8A4F0F6'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"298F55BC-0709-57F3-9D03-8449D8A4F0F6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Lats","Shoulders","Forearms"],"name":"Front Lever","notes":"","plannedSets":3,"proTips":["Start by hanging from a pull-up bar with an overhand grip, hands shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","Bend your knees and tuck them towards your chest.","Simultaneously, lift your legs up and extend them straight out in front of you, keeping your body parallel to the ground.","Hold this position for as long as you can, aiming for a full front lever position.","To release, slowly lower your legs back down and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AEBD816D-4AC0-5338-9793-AA6B92298748","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('824F5BAA-70DE-5383-B3BD-0C907FC3F488'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"824F5BAA-70DE-5383-B3BD-0C907FC3F488","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Core","Shoulders"],"name":"Front Lever Reps","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with an overhand grip, palms facing away from you.","Engage your core and pull your shoulder blades down and back.","Keeping your body straight, lift your legs up until they are parallel to the ground.","Hold this position for as long as you can, aiming for 10-20 seconds.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"03FE8F96-2D7E-5B5A-866C-E8E5A134BF90","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A9FA5F30-F28B-54CE-A00E-4465DC083279'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A9FA5F30-F28B-54CE-A00E-4465DC083279","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Shoulders"],"name":"Front Plank With Twist","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe.","Engage your core and glutes to maintain a stable position.","Rotate your torso to the right, lifting your right arm and extending it towards the ceiling.","Keep your hips and legs stable as you twist.","Hold for a moment, then return to the starting position.","Repeat the twist on the left side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8978FD61-1936-50AC-90E8-C32555DC70B6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2870822A-7E1B-5131-B040-6E65C883B12B'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2870822A-7E1B-5131-B040-6E65C883B12B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Chest"],"name":"Full Maltese","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and your arms extended straight out to the sides.","Slowly lean forward, keeping your arms straight, until your upper body is parallel to the ground.","Engage your core and hold this position for a few seconds.","Return to the starting position by pushing through your feet and standing back up.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"24815D1E-77B7-5FD3-BF72-AB3ADD3D9C2C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9E4B20BF-022B-59F8-8291-8025F9FE8839'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9E4B20BF-022B-59F8-8291-8025F9FE8839","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Chest","Triceps"],"name":"Full Planche","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands shoulder-width apart and your fingers pointing forward.","Engage your core and slowly shift your weight forward, lifting your feet off the ground.","Continue shifting your weight forward until your body is parallel to the ground, balancing on your hands.","Hold this position for as long as you can, maintaining a straight body line.","Slowly lower your feet back to the ground and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4305582C-7CED-5C9B-9754-E436A60C8864","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3DC1842B-F226-5FC0-BFCE-763084B59377'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3DC1842B-F226-5FC0-BFCE-763084B59377","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps","Core"],"name":"Full Planche Push-Up","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands placed slightly wider than shoulder-width apart.","Engage your core and lower your body down towards the ground, keeping your elbows close to your sides.","As you lower yourself, lean your body forward and lift your feet off the ground, balancing on your hands.","Continue to lower your body until your chest is just above the ground.","Push through your hands and extend your arms to lift your body back up to the starting position.","Maintain a straight line from your head to your heels throughout the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AC79EE9D-32E6-5548-A84F-11728BB2BB86","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0846ADA7-0D1F-562B-AF63-4F21DFCDC30C'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0846ADA7-0D1F-562B-AF63-4F21DFCDC30C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Gironda Sternum Chin","notes":"","plannedSets":3,"proTips":["Stand facing a high bar with your feet shoulder-width apart.","Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your lats and biceps to pull your chest up towards the bar, leading with your sternum.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"540EB175-E132-591D-BCC7-71BCD9AF9BA5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('63CF67BC-16CE-5B81-AB64-00979993D534'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"63CF67BC-16CE-5B81-AB64-00979993D534","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Glute Bridge March","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.","While keeping your hips lifted, lift one foot off the ground and bring your knee towards your chest.","Lower your foot back to the ground and repeat the movement with the other leg.","Continue alternating legs in a marching motion while maintaining the bridge position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2E5268AD-8970-5D5E-BEC7-8E94FD68193B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E92EFFAE-A2A0-53F9-82E8-52932B31F7AC'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E92EFFAE-A2A0-53F9-82E8-52932B31F7AC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Core"],"name":"Glute Bridge Two Legs On Bench","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench with your back against it and your feet flat on the ground.","Place your hands on the bench beside your hips for support.","Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1D01B84C-19AE-5961-84E4-7B28283E391F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E9BAF416-B249-57D7-A746-8B6A410BF537'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E9BAF416-B249-57D7-A746-8B6A410BF537","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Lower Back"],"name":"Glute-Ham Raise","notes":"","plannedSets":3,"proTips":["Adjust the glute-ham raise machine to fit your body.","Position yourself face down on the machine with your ankles secured.","Place your hands on your chest or cross them over your chest.","Engage your hamstrings and glutes to lift your upper body up towards the ceiling.","Continue lifting until your body is in a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"947B561D-211A-54B4-A502-3B0FA2EF44A5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EEB0C8BA-9F8A-5F7C-A1A4-92615FBF8247'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"EEB0C8BA-9F8A-5F7C-A1A4-92615FBF8247","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Forearms","Biceps"],"name":"Gorilla Chin","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp a pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your palms facing away from you.","Engage your core and pull your body up towards the bar, bringing your chin above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"69C5F891-F2A8-58DD-BBD5-67F913FAAD46","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('476E2125-B474-5463-BC72-79DA4C2BE706'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"476E2125-B474-5463-BC72-79DA4C2BE706","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Inner Thighs"],"name":"Groin Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your legs off the ground, bringing your knees towards your chest.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"123D9FA3-6CEE-5A05-95F3-EC8A2D3420B1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F1455ADF-08DB-5D97-A23C-5BD06F5799C8'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"F1455ADF-08DB-5D97-A23C-5BD06F5799C8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Hack Calf Raise","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to a comfortable weight.","Stand on the sled machine with your toes on the platform and your heels hanging off.","Hold onto the handles for stability.","Raise your heels as high as possible by pushing through the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"FC2F4FEB-1A15-5DD8-B8A7-6DE837E980D1","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"9FAAD586-602C-5D83-9120-6AA779943082","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('29BE89BC-34ED-5072-BD7B-82EEF34DAAAE'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"29BE89BC-34ED-5072-BD7B-82EEF34DAAAE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Hack One Leg Calf Raise","notes":"","plannedSets":3,"proTips":["Adjust the sled machine to an appropriate weight.","Stand on the sled machine with one foot, keeping the other foot off the ground.","Hold onto the handles for stability.","Raise your heel as high as possible, lifting your body up on the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions.","Switch legs and repeat the exercise."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"EE83A3D0-CDBC-5D23-B07D-750A05F2483E","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"72F0E2A5-C5D9-5DCD-B443-7D31C2AF7703","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('709DF8CD-49BF-5A5A-87AD-42144C8C253F'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"709DF8CD-49BF-5A5A-87AD-42144C8C253F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Glutes"],"name":"Half Knee Bends","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body down as if you were sitting back into a chair.","Keep your chest up and your weight in your heels.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('0493E9F9-DB3F-599E-9810-E790E3BC8D30'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0493E9F9-DB3F-599E-9810-E790E3BC8D30","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Half Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BD67F8CB-78E7-5053-9CE2-EBDD76131D48","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('78544F0B-C152-5405-BBEB-FB5A390E2240'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"78544F0B-C152-5405-BBEB-FB5A390E2240","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes"],"name":"Hamstring Stretch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Step forward with your right foot and shift your weight onto your right leg.","Keeping your back straight, slowly bend forward at the hips, reaching towards your right foot with both hands.","Hold the stretch for 20-30 seconds, then return to the starting position.","Repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"A6E08BEA-358F-500E-9AF8-119242F76976","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('6A27B914-32BC-51FF-9177-80DECEAA6855'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cardio Machine","hint":"","id":"6A27B914-32BC-51FF-9177-80DECEAA6855","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Hands Bike","notes":"","plannedSets":3,"proTips":["Adjust the seat height and handlebar position to a comfortable level.","Sit on the ergometer with your back straight and feet on the pedals.","Grasp the handles with your hands and position your arms at a 90-degree angle.","Start pedaling with your hands, pushing and pulling the handles in a controlled motion.","Continue pedaling for the desired duration or number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('EB2DF803-18E1-575A-88C1-D5C620399188'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"EB2DF803-18E1-575A-88C1-D5C620399188","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Calves"],"name":"Hands Clasped Circular Toe Touch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your hands clasped together in front of your chest.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower your hands towards your toes in a circular motion, reaching as far as you can without straining.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"99778147-5C4E-5980-8FBA-65D48270A354","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('06A97B7B-2583-5BAE-9118-2523D58CE6CE'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"06A97B7B-2583-5BAE-9118-2523D58CE6CE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Calves"],"name":"Hands Reversed Clasped Circular Toe Touch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your arms extended to the sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down with your hands and clasp them together behind your legs.","Slowly raise your hands up and over your head in a circular motion, keeping your legs straight.","Continue the circular motion until your hands touch your toes.","Reverse the motion and bring your hands back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F940B0F2-2694-512F-8B47-627754B9F621","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('340E7FE0-5E1D-5600-962F-404B142A27FD'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"340E7FE0-5E1D-5600-962F-404B142A27FD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Core"],"name":"Handstand","notes":"","plannedSets":3,"proTips":["Find an open space with enough room to perform a handstand.","Place your hands on the ground shoulder-width apart, fingers pointing forward.","Kick your legs up towards the wall, using your core and shoulders to maintain balance.","Once in a handstand position, engage your triceps to support your body weight.","Hold the handstand for as long as you can maintain balance.","To come down, slowly lower your legs back to the ground.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9D90F7C4-5A10-57FA-8288-DC0B908165E2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A1546B57-8950-5BDB-841D-55C07880B2E8'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A1546B57-8950-5BDB-841D-55C07880B2E8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Chest","Core"],"name":"Handstand Push-Up","notes":"","plannedSets":3,"proTips":["Find a wall and face away from it, standing a few feet away.","Place your hands on the ground shoulder-width apart and kick your feet up against the wall, coming into a handstand position.","Bend your elbows and lower your head towards the ground, keeping your body in a straight line.","Push through your hands and extend your arms to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"184CE249-2A86-51B6-B815-975C0E3289BA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5B05B988-EE77-504C-9C21-68395CBBDD55'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"5B05B988-EE77-504C-9C21-68395CBBDD55","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Hanging Leg Hip Raise","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up by flexing your hips and knees until your thighs are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D4671BC4-154E-5032-BC3F-180CF8B66AFE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BF6A923B-8494-5EF1-882A-0500DD02C838'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"BF6A923B-8494-5EF1-882A-0500DD02C838","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Hanging Leg Raise","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"64E4663E-F659-574A-979B-64E7D3A3B470","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('92D20EFC-ADD8-5FDB-A296-E68DD8B742D7'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"92D20EFC-ADD8-5FDB-A296-E68DD8B742D7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Hanging Oblique Knee Raise","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your knees towards your chest, twisting your torso to the side as you do so.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat on the other side, twisting your torso in the opposite direction.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"662AABAA-93F4-5D69-8708-D82300F8A785","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('38227C4A-FFCA-5AAF-8B59-87627DCC2E2E'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"38227C4A-FFCA-5AAF-8B59-87627DCC2E2E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Shoulders"],"name":"Hanging Pike","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up towards the bar, keeping them straight.","Continue lifting until your body forms a ''V'' shape, with your legs parallel to the ground.","Hold the position for a moment, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F7DA12AF-AAFE-5904-9BBB-A29A6BBFAC93","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DAA2E2F7-B675-5125-8873-8F46F98F02B8'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DAA2E2F7-B675-5125-8873-8F46F98F02B8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Hanging Straight Leg Hip Raise","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F8985FC0-5535-5AC3-9459-DE687CB80507","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7B51D44C-8552-530F-A25D-BDF275042639'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"7B51D44C-8552-530F-A25D-BDF275042639","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Hanging Straight Leg Raise","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F24304D8-6E99-5342-9B5D-04DBAC2F605A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C109F0BC-F1B7-5C93-92F7-0328BAD6CB84'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C109F0BC-F1B7-5C93-92F7-0328BAD6CB84","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Hip Flexors"],"name":"Hanging Straight Twisting Leg Hip Raise","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your legs straight.","Engage your core and lift your legs up towards your chest, keeping them straight.","Once your legs are parallel to the ground, twist your hips to one side, bringing your legs towards that side.","Pause for a moment, then return to the starting position.","Repeat the movement, but this time twist your hips to the opposite side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1351BAFD-43AB-570D-A0C2-4D0E45E76C29","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2140166A-2A49-5512-A233-24E7E5E9CA97'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2140166A-2A49-5512-A233-24E7E5E9CA97","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Glutes","Calves"],"name":"High Knee Against Wall","notes":"","plannedSets":3,"proTips":["Stand facing a wall with your feet hip-width apart.","Place your hands on the wall for support.","Engage your core and lift your right knee up towards your chest, while keeping your left foot on the ground.","Quickly switch legs, bringing your left knee up towards your chest and lowering your right foot back down.","Continue alternating legs in a running motion, bringing your knees up as high as possible.","Maintain a fast pace and keep your upper body stable throughout the exercise.","Repeat for the desired duration or number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('ABDCA85C-B212-557C-9433-849A7AA8F2CE'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"ABDCA85C-B212-557C-9433-849A7AA8F2CE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Glutes","Hamstrings"],"name":"Hip Raise (Bent Knee)","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides, palms facing down.","Engage your core and glutes, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E75E0871-11CD-5AEA-B765-2562922F20B6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4AE59E21-42E8-5631-BF0E-BD29E0EDDC9E'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"4AE59E21-42E8-5631-BF0E-BD29E0EDDC9E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Hug Keens To Chest","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position.","As you squat down, bring your knees up towards your chest and hug them with your arms.","Hold this position for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6DEF9483-41AF-5498-AA2D-1A876C885B5E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('80EFC2AC-104C-5BB2-8C5B-D7793D344DF7'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"80EFC2AC-104C-5BB2-8C5B-D7793D344DF7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders"],"name":"Hyght Dumbbell Fly","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, with a slight bend in your elbows.","Keeping a slight bend in your elbows, lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"45A63230-447B-5581-98D1-FAC65C40A11F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B193BB02-6074-5FFC-B093-F4F7AA299EB6'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B193BB02-6074-5FFC-B093-F4F7AA299EB6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Hyperextension","notes":"","plannedSets":3,"proTips":["Adjust the hyperextension bench so that your upper thighs are resting on the pad and your feet are secured.","Cross your arms over your chest or place your hands behind your head.","Lower your upper body towards the ground while keeping your back straight.","Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F943DAE3-F55D-507A-B6E3-3C5563E7DBB3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B0FB381A-7285-5849-B53C-D63A1D432290'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B0FB381A-7285-5849-B53C-D63A1D432290","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Hyperextension (On Bench)","notes":"","plannedSets":3,"proTips":["Adjust the hyperextension bench so that your hips are resting comfortably on the pad and your feet are secured.","Cross your arms over your chest or place your hands behind your head.","Slowly lower your upper body towards the ground while keeping your back straight.","Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F418D9FF-2A6C-5776-99B4-8A85245FBC1A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0E4BD846-8579-59E1-9CF6-D8D0426A8972'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0E4BD846-8579-59E1-9CF6-D8D0426A8972","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Impossible Dips","notes":"","plannedSets":3,"proTips":["Position yourself between two parallel bars with your arms fully extended and your body suspended in the air.","Bend your knees and cross your ankles.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0AB06B33-D7C5-5C62-A6C0-E9BE6225A7FB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('73AC0370-1E30-5709-B4D7-1603E7F0EE7A'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"73AC0370-1E30-5709-B4D7-1603E7F0EE7A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Hamstrings"],"name":"Inchworm","notes":"","plannedSets":3,"proTips":["Start in a standing position with your feet hip-width apart.","Bend forward at the waist and place your hands on the ground in front of you.","Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe.","Pause for a moment, then walk your hands back towards your feet, keeping your legs as straight as possible.","Once your hands reach your feet, stand back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"241EDF0E-ADE4-50F7-97F6-A584354F42DB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('28C08BC4-5D4F-5F65-AABC-72A22521DB00'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"28C08BC4-5D4F-5F65-AABC-72A22521DB00","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Hamstrings"],"name":"Inchworm V. 2","notes":"","plannedSets":3,"proTips":["Start in a standing position with your feet hip-width apart.","Bend forward at the waist and place your hands on the ground in front of you.","Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe.","Keeping your legs straight, walk your feet towards your hands, bringing your hips up towards the ceiling.","Continue walking your hands forward, repeating the movement for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"307F27CA-FEFD-577E-861F-E9A6F0612C0C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('776EAD32-171F-5742-AF65-FF97A1FDE00F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"776EAD32-171F-5742-AF65-FF97A1FDE00F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Incline Close-Grip Push-Up","notes":"","plannedSets":3,"proTips":["Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, with your body forming a straight line from head to heels.","Lower your chest towards the elevated surface by bending your elbows, keeping them close to your sides.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8E9957FA-21AB-519C-915D-8621B6DB469C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4EFBD1CD-E83D-52AE-A1E1-11E6C523F4D7'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"4EFBD1CD-E83D-52AE-A1E1-11E6C523F4D7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Incline Leg Hip Raise (Leg Straight)","notes":"","plannedSets":3,"proTips":["Lie on an incline bench with your back flat against the bench and your legs extended straight out in front of you.","Place your hands on the sides of the bench for support.","Engaging your abs, lift your legs off the bench, raising them as high as you can while keeping them straight.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BF0B590D-BBE9-53B6-AEE4-FAA6C7384543","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3D960FFE-FF57-53FD-8947-7BF973644740'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3D960FFE-FF57-53FD-8947-7BF973644740","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Incline Push Up Depth Jump","notes":"","plannedSets":3,"proTips":["Find an elevated surface, such as a bench or step, and place your hands shoulder-width apart on the edge.","Step your feet back, keeping your body in a straight line from head to heels.","Lower your chest towards the edge of the surface, bending your elbows and keeping your body aligned.","Push through your palms to extend your arms and return to the starting position.","Jump off the edge of the surface, landing softly with your knees slightly bent.","Repeat the push-up and depth jump for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7879B6FE-1DA2-5A20-9A46-C57DD4E5DB73","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E71399D7-1F48-5839-B230-1B47AD70F5C5'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E71399D7-1F48-5839-B230-1B47AD70F5C5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Incline Push-Up","notes":"","plannedSets":3,"proTips":["Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.","Lower your chest towards the elevated surface by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"49CA2DF4-F23C-5C88-BF5E-BD25791338BC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BBFA4EE7-FB87-5A96-AB8C-F549378320E8'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"BBFA4EE7-FB87-5A96-AB8C-F549378320E8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Incline Push-Up (On Box)","notes":"","plannedSets":3,"proTips":["Place your hands on the edge of a box or elevated surface, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.","Lower your chest towards the box by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7AA51AAC-9121-5327-84FF-284B2BDEC9E0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B1946E86-7051-5050-AE4E-6E8895F70BF7'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B1946E86-7051-5050-AE4E-6E8895F70BF7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Incline Reverse Grip Push-Up","notes":"","plannedSets":3,"proTips":["Place your hands on the edge of a bench or elevated surface, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.","Lower your chest towards the bench by bending your elbows, keeping them close to your sides.","Pause for a moment at the bottom, then push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5B1A8C36-D326-57AE-918A-3ADFB7F9F014","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('95250772-A830-52FA-9960-278B95218676'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"95250772-A830-52FA-9960-278B95218676","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Serratus Anterior","Triceps","Shoulders"],"name":"Incline Scapula Push Up","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Place your hands on the bench slightly wider than shoulder-width apart.","Position your feet on the ground, hip-width apart.","Lower your chest towards the bench, keeping your elbows tucked in.","As you lower, retract your shoulder blades, squeezing your scapulae together.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"415D626C-9919-5128-AFB3-9DAC66DF7CD1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DEAC29FA-97C6-5F6C-8966-B05611893519'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DEAC29FA-97C6-5F6C-8966-B05611893519","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Incline Twisting Sit-Up","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet secured under the foot pads.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body off the bench, curling forward.","As you curl up, twist your torso to one side, bringing your elbow towards the opposite knee.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat the movement, this time twisting your torso to the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D0CE6960-C9EB-5C94-B2B4-6F3BF57F3CDC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E620650B-F17A-5AD3-B9C9-15D80B83FCD3'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Rope","hint":"","id":"E620650B-F17A-5AD3-B9C9-15D80B83FCD3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Glutes"],"name":"Intermediate Hip Flexor And Quad Stretch","notes":"","plannedSets":3,"proTips":["Stand upright with your feet shoulder-width apart.","Hold onto a stable object for support.","Bend your right knee and bring your right foot towards your glutes, grabbing the rope with your right hand.","Slowly pull your right foot towards your glutes, feeling a stretch in your right quad.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the left side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"558CC013-7FD2-5F4A-A055-C3AD606AD11C","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('C1CD6D32-A7BF-51E4-BE8B-97F4B78B2D4C'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C1CD6D32-A7BF-51E4-BE8B-97F4B78B2D4C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Calves"],"name":"Inverse Leg Curl (Bench Support)","notes":"","plannedSets":3,"proTips":["Lie face down on a bench with your hips at the edge and your legs extended straight behind you.","Hold onto the bench for support.","Keeping your upper body still, bend your knees and curl your legs towards your glutes.","Pause for a moment at the top, then slowly extend your legs back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"684EB835-42B8-5F3B-B7C4-C7BF4BDDF1E6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0582E194-4B37-58E1-BE20-EA6BB6283C22'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0582E194-4B37-58E1-BE20-EA6BB6283C22","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Calves"],"name":"Inverse Leg Curl (On Pull-Up Cable Machine)","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the ankle straps are at the lowest setting.","Lie face down on the bench with your legs extended and the ankle straps attached to your feet.","Hold onto the handles of the bench for stability.","Bend your knees and curl your legs towards your glutes, squeezing your hamstrings.","Pause for a moment at the top of the movement, then slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E5FE1EF3-D31F-5898-A538-17DA18988662","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5117130F-1FE0-5887-AEF9-613E3C82DC0A'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"5117130F-1FE0-5887-AEF9-613E3C82DC0A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Inverted Row","notes":"","plannedSets":3,"proTips":["Set up a bar at waist height or use a suspension trainer.","Stand facing the bar or suspension trainer, with your feet shoulder-width apart.","Grab the bar or handles with an overhand grip, slightly wider than shoulder-width apart.","Lean back, keeping your body straight and your heels on the ground.","Pull your chest towards the bar or handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B4B4235A-249C-5D82-AFCD-27DFD023F907","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DC380E1E-3470-594E-9F75-DF66CD1A25DA'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DC380E1E-3470-594E-9F75-DF66CD1A25DA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Inverted Row Bent Knees","notes":"","plannedSets":3,"proTips":["Set up a bar at waist height and lie underneath it.","Grab the bar with an overhand grip, slightly wider than shoulder-width apart.","Position your body so that your heels are on the ground and your body is straight.","Pull your chest up towards the bar by squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8E8164DD-031E-53FF-B42A-5A66AE2802DD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FC0947B4-601C-5FAA-BD79-3E0ED07BCC69'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"FC0947B4-601C-5FAA-BD79-3E0ED07BCC69","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Inverted Row On Bench","notes":"","plannedSets":3,"proTips":["Set up a bench at a height that allows your body to hang freely underneath it.","Lie face up on the ground with your head towards the bench.","Reach up and grab the bench with an overhand grip, slightly wider than shoulder-width apart.","Position your body so that your heels are on the ground and your arms are fully extended.","Engage your core and squeeze your shoulder blades together as you pull your chest up towards the bench.","Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"99B95B72-23CD-5C3F-A1D0-025C84EDA68A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CEE59AA9-8344-57C0-BB13-E40BDA05A481'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CEE59AA9-8344-57C0-BB13-E40BDA05A481","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Inverted Row V. 2","notes":"","plannedSets":3,"proTips":["Set up a bar at waist height on a Smith machine or use a suspension trainer.","Stand facing the bar or suspension trainer and grab it with an overhand grip, hands shoulder-width apart.","Walk your feet forward, leaning back until your body is at a slight angle.","Keep your body straight and pull your chest up towards the bar or handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E0483A90-1B0B-5337-93D4-980DEDF21A60","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('26D531DB-57D9-51A4-B5BC-1DCC92B5AF3E'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"26D531DB-57D9-51A4-B5BC-1DCC92B5AF3E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Inverted Row With Straps","notes":"","plannedSets":3,"proTips":["Set up a suspension trainer or straps at chest height.","Stand facing the anchor point and grab the handles with an overhand grip.","Walk your feet forward, leaning back until your body is at an angle.","Keep your body straight and engage your core.","Pull your chest towards the handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"90AD2833-D936-5D80-A1F2-E296B19A0E59","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CA961CFD-1CF3-5B7B-8241-BF8EE9FCD320'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CA961CFD-1CF3-5B7B-8241-BF8EE9FCD320","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Iron Cross Stretch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your arms extended out to the sides.","Raise your legs up towards the ceiling, keeping them straight.","Slowly lower your legs to one side, aiming to touch the floor with your feet.","Hold the stretch for a few seconds, then return your legs to the starting position.","Repeat the stretch on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"4EF6E943-6C09-562E-A3A4-E33F06ECD6B4","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('B9D21A1B-293E-582B-B77B-5F7942DF93ED'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B9D21A1B-293E-582B-B77B-5F7942DF93ED","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Isometric Chest Squeeze","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out in front of you, parallel to the ground, with your palms facing each other.","Squeeze your chest muscles together as hard as you can, while keeping your arms straight.","Hold this position for a few seconds, focusing on contracting your chest muscles.","Release the squeeze and relax your chest muscles.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CB73A4F3-548B-5F19-B6A0-AFF9599A4574","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9EF8612A-EE68-5DA8-BC62-0603EB0C166A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9EF8612A-EE68-5DA8-BC62-0603EB0C166A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps","Core"],"name":"Isometric Wipers","notes":"","plannedSets":3,"proTips":["Start by lying flat on your back on a mat or bench.","Extend your arms straight out to the sides, perpendicular to your body.","Engage your core and lift both legs off the ground, keeping them together and straight.","Slowly lower your legs to one side, aiming to touch the ground with your feet while maintaining control.","Pause for a moment, then use your core to lift your legs back to the starting position.","Repeat the movement, this time lowering your legs to the opposite side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0713D37E-6D89-5E36-BD86-152F51B83673","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CBB7AF4C-BEE4-57D3-8DBD-75DFBE339A1D'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CBB7AF4C-BEE4-57D3-8DBD-75DFBE339A1D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves","Shoulders","Triceps","Core"],"name":"Jack Burpee","notes":"","plannedSets":3,"proTips":["Start in a standing position with your feet shoulder-width apart.","Lower your body into a squat position, placing your hands on the ground in front of you.","Kick your feet back, landing in a push-up position.","Perform a push-up, lowering your chest to the ground and then pushing back up.","Jump your feet forward, landing in a squat position.","Jump up explosively, reaching your arms overhead.","Land softly and immediately lower back into the squat position to begin the next repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('6B7C2A49-8CFE-523E-8F9C-0C774784170C'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6B7C2A49-8CFE-523E-8F9C-0C774784170C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Calves"],"name":"Jack Jump","notes":"","plannedSets":3,"proTips":["Stand with your feet together and your arms by your sides.","Jump up, spreading your feet apart and raising your arms above your head.","As you land, quickly jump back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('44F69219-9E68-555B-8745-47666D2F8E26'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"44F69219-9E68-555B-8745-47666D2F8E26","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Jackknife Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and your arms overhead.","Engage your core and lift your legs and upper body simultaneously, reaching your hands towards your toes.","Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2A98B345-8EEF-57F7-910D-898F8888E2C0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('25A85DFB-F660-579A-946F-46A80A946BDA'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"25A85DFB-F660-579A-946F-46A80A946BDA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Janda Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F33BF862-178A-5647-B859-4DD64A18C4D9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B1C4CC1F-E018-5E8F-A1A2-ED1E62FB848B'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Rope","hint":"","id":"B1C4CC1F-E018-5E8F-A1A2-ED1E62FB848B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Calves","Quadriceps","Hamstrings","Glutes"],"name":"Jump Rope","notes":"","plannedSets":3,"proTips":["Hold the handles of the jump rope with your hands, palms facing inward.","Stand with your feet shoulder-width apart and knees slightly bent.","Swing the rope over your head and jump over it as it comes towards your feet.","Land softly on the balls of your feet and repeat the jump as the rope comes around again.","Continue jumping for the desired duration or number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('7226242D-2850-571D-B6A8-9230708A90D6'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"7226242D-2850-571D-B6A8-9230708A90D6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Jump Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump explosively off the ground, extending your hips, knees, and ankles.","While in mid-air, quickly bring your arms forward for balance.","Land softly on the balls of your feet and immediately go into the next repetition.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4B7494AB-D0F5-5D66-B1D7-E9C8D5F09ADC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8B73A60E-0435-52B2-993F-F806A2E88022'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"8B73A60E-0435-52B2-993F-F806A2E88022","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Jump Squat V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump explosively, extending your hips and knees fully.","Land softly on the balls of your feet and immediately lower your body back into a squat position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0000F30F-65B6-5CEA-BBA3-89BE0918B3FF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9BD71074-B8B7-5C35-91A3-D06B840BD7FD'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"9BD71074-B8B7-5C35-91A3-D06B840BD7FD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Shoulders"],"name":"Kettlebell Advanced Windmill","notes":"","plannedSets":3,"proTips":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold a kettlebell in your right hand, with your arm extended overhead and your palm facing forward.","Rotate your left foot slightly to the right, and shift your weight onto your left leg.","Bend your left knee and hinge at the hip, lowering your torso towards the left side.","Keep your right arm extended overhead and your eyes on the kettlebell.","As you lower your torso, allow your right leg to straighten and your right foot to pivot slightly.","Lower your torso until you feel a stretch in your left hamstring and your right arm is pointing towards the ground.","Pause for a moment, then engage your core and push through your left heel to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B47725A2-81BD-5A0D-AE38-959E5E80E0FA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E57A5C73-E22B-5F78-BD71-CBCAF2544DFD'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"E57A5C73-E22B-5F78-BD71-CBCAF2544DFD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Shoulders","Traps","Core"],"name":"Kettlebell Alternating Hang Clean","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Allow the kettlebells to hang in front of your body with your arms fully extended.","In one fluid motion, explosively extend your hips, shrug your shoulders, and pull the kettlebells up towards your shoulders.","As the kettlebells reach shoulder height, rotate your wrists and catch the kettlebells in the rack position, with your palms facing inward and the kettlebells resting on the outside of your forearms.","Lower the kettlebells back down to the starting position and repeat the movement with the opposite arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"38354B2E-C2F8-59CC-A9BD-D7613EDE4D80","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7104E886-B4A5-5E0E-8E1F-D3A07E6CAF2E'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"7104E886-B4A5-5E0E-8E1F-D3A07E6CAF2E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Kettlebell Alternating Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.","Press one kettlebell overhead, fully extending your arm.","Lower the kettlebell back to shoulder height.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"09DF175E-A01F-5194-98B0-8A481BD30A1B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F344520A-C832-5645-BD82-A8B7EE3DBC05'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"F344520A-C832-5645-BD82-A8B7EE3DBC05","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Kettlebell Alternating Press On Floor","notes":"","plannedSets":3,"proTips":["Start by lying on your back on the floor with your knees bent and feet flat on the ground.","Hold a kettlebell in each hand, with your palms facing towards your feet and your arms extended straight up towards the ceiling.","Lower one kettlebell down towards your shoulder while keeping the other kettlebell extended straight up.","Press the lowered kettlebell back up to the starting position while simultaneously lowering the other kettlebell down towards your shoulder.","Continue alternating the press motion with each kettlebell for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D5B3CC2A-2780-503A-9EF5-9B189DB74053","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AA81DE39-D16D-559F-BC93-353BD4D6FA15'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"AA81DE39-D16D-559F-BC93-353BD4D6FA15","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Core","Shoulders"],"name":"Kettlebell Alternating Renegade Row","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands gripping the kettlebells and your feet hip-width apart.","Engage your core and keep your body in a straight line from head to heels.","Pull one kettlebell up towards your chest, keeping your elbow close to your body.","Lower the kettlebell back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7ABD3CD9-288E-5071-BC0E-E4EF2D1D2FA8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FB674652-4F76-5AB8-9EF6-6E7A43C02F59'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"FB674652-4F76-5AB8-9EF6-6E7A43C02F59","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Kettlebell Alternating Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull one kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Lower the kettlebell back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DC4D265A-2C8D-5481-8BE5-121556C56A43","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4F0A889E-0AD1-52C6-B405-025738F481D9'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"4F0A889E-0AD1-52C6-B405-025738F481D9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Kettlebell Arnold Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height with your palms facing towards you.","Engage your core and press the kettlebells overhead, rotating your palms to face forward as you extend your arms.","Pause at the top of the movement, then slowly lower the kettlebells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F3CE39C7-D331-5EDD-BCC1-6214B09A1E0D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2CB2822C-D3BA-5A1E-9124-95EB00AA8CEC'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"2CB2822C-D3BA-5A1E-9124-95EB00AA8CEC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Triceps","Obliques"],"name":"Kettlebell Bent Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in your right hand.","Bend your knees slightly and press the kettlebell overhead with your right arm, keeping your elbow locked.","Rotate your torso to the left, shifting your weight onto your left foot.","Bend your left knee and lower your torso towards the ground, keeping your right arm extended overhead.","As you lower, keep your eyes on the kettlebell and your chest lifted.","Once your left hand touches the ground, push through your left foot and straighten your left leg, driving your hips forward.","As you drive your hips forward, use your core and right arm to press the kettlebell back up to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4394119E-2B6C-58B9-92B0-0B9BC8145AC5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C659578F-EB5A-561D-ADF7-143F7BF5FB5A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"C659578F-EB5A-561D-ADF7-143F7BF5FB5A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Kettlebell Bottoms Up Clean From The Hang Position","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Allow the kettlebell to hang down between your legs, with your arm fully extended.","In one fluid motion, explosively extend your hips and knees while pulling the kettlebell up towards your shoulder.","As the kettlebell reaches shoulder height, rotate your wrist so that the bottom of the kettlebell is facing up.","Catch the kettlebell at shoulder height with your elbow bent and your palm facing up.","Lower the kettlebell back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2234EA2C-73A3-569A-B3DF-1BCBCC0B500A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9000AA4F-E607-5727-A0C7-2AA2AC6B9944'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"9000AA4F-E607-5727-A0C7-2AA2AC6B9944","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Kettlebell Double Alternating Hang Clean","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Allow the kettlebells to hang straight down in front of your body.","In one fluid motion, explosively extend your hips and knees while shrugging your shoulders.","As the kettlebells rise, pull them up towards your shoulders, keeping your elbows high and out to the sides.","Catch the kettlebells at shoulder height, with your palms facing inward and your elbows pointing forward.","Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"987BEAB3-0874-5716-A0E0-7DAE62D846DC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1BF2DE03-4EB9-5F43-9542-98B64FFD232C'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"1BF2DE03-4EB9-5F43-9542-98B64FFD232C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Kettlebell Double Jerk","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.","Bend your knees slightly and engage your core.","Press the kettlebells overhead, fully extending your arms.","Bend your knees and quickly drop into a partial squat.","Explosively extend your hips and knees, driving the kettlebells overhead.","Lock out your arms and catch the kettlebells overhead with your knees slightly bent.","Stand up straight and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FE470764-6AD3-54F2-BA40-A3AD2709261F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0D751ED0-AF7F-5358-AA85-8E8E80320ECB'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"0D751ED0-AF7F-5358-AA85-8E8E80320ECB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Kettlebell Double Push Press","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.","Bend your knees slightly and engage your core.","Initiate the movement by explosively extending your hips, knees, and ankles, driving the kettlebells overhead.","As the kettlebells reach the top, press them fully overhead, locking out your arms.","Lower the kettlebells back to the starting position by bending your elbows and bringing them back down to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FC2EC795-A697-5D25-8478-54452E3F05E8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3BD3B6B0-82B6-5AAA-B0EE-D0AE7D974BE4'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"3BD3B6B0-82B6-5AAA-B0EE-D0AE7D974BE4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Forearms","Core"],"name":"Kettlebell Double Snatch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at arm''s length in front of your thighs.","Bend your knees slightly and hinge forward at the hips, keeping your back flat and chest up.","In one explosive motion, extend your hips, knees, and ankles, and simultaneously pull the kettlebells up towards your shoulders.","As the kettlebells reach shoulder level, rotate your wrists and punch the kettlebells overhead, fully extending your arms.","Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"34D667B9-EE22-5E05-BD74-9553DD638E06","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EE80D27C-D5D1-5E91-A5CF-F20167C72AA9'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"EE80D27C-D5D1-5E91-A5CF-F20167C72AA9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Hamstrings"],"name":"Kettlebell Double Windmill","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in your right hand.","Extend your right arm overhead, keeping your eyes on the kettlebell.","Rotate your left foot 45 degrees to the left and your right foot 90 degrees to the right.","Bend at the waist to the left, keeping your right arm extended overhead.","Lower the kettlebell towards the ground, reaching towards your left foot.","Pause for a moment, then engage your core and push through your right foot to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"876DF6C0-CCBA-5FF5-8929-C71CC4A13353","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('690296CB-932E-53E6-A2A8-EE7C1797E868'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"690296CB-932E-53E6-A2A8-EE7C1797E868","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Kettlebell Extended Range One Arm Press On Floor","notes":"","plannedSets":3,"proTips":["Start by lying on your back on the floor with your knees bent and feet flat on the ground.","Hold a kettlebell in one hand, with your palm facing towards your feet.","Extend your arm straight up towards the ceiling, keeping your elbow locked and your wrist straight.","Slowly lower the kettlebell back down to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C3A47C5A-6C59-5A2D-9875-660B5CF6A6DA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1B172957-AD54-50FC-B747-4C8C0AAD15D3'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"1B172957-AD54-50FC-B747-4C8C0AAD15D3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Forearms"],"name":"Kettlebell Figure 8","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pass the kettlebell between your legs, switching hands as it reaches the back of your legs.","As the kettlebell comes forward, pass it to the other hand between your legs.","Continue passing the kettlebell between your legs in a figure 8 motion.","Maintain a steady pace and engage your core throughout the exercise.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"88C539F0-4BED-5CC6-95AE-43A7B584CC77","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('37BE77EB-6A29-57B3-BF79-0058AD52CAF0'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Kettlebell","hint":"","id":"37BE77EB-6A29-57B3-BF79-0058AD52CAF0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Kettlebell Front Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the kettlebell with both hands in front of your chest, close to your body.","Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F882554F-59DD-5146-A525-A128CFB7CE4A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('65E916DB-5B1A-5E2D-888F-D6CBE66A20A0'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Kettlebell","hint":"","id":"65E916DB-5B1A-5E2D-888F-D6CBE66A20A0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Kettlebell Goblet Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell close to your chest with both hands.","Keeping your chest up and core engaged, lower your body down into a squat position by bending at the knees and hips.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0BB4E206-9453-5933-A3FC-4BF692163001","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('69AADDAE-E7F7-5D84-B1FE-AE191936757B'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"69AADDAE-E7F7-5D84-B1FE-AE191936757B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Quadriceps","Calves"],"name":"Kettlebell Hang Clean","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower the kettlebell towards the ground, allowing it to swing between your legs.","Quickly extend your hips and knees, using the momentum to swing the kettlebell up to shoulder height.","As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbow tucked in and the kettlebell resting on your forearm.","Lower the kettlebell back down to the starting position between your legs, and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CC864F85-1D70-5A82-9817-75E8F65DE543","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C63745CB-A28C-5C3D-9CB0-D3895C2D309C'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"C63745CB-A28C-5C3D-9CB0-D3895C2D309C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Kettlebell Lunge Pass Through","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands.","Take a step forward with your right foot, lowering your body into a lunge position.","As you lunge forward, pass the kettlebell under your right thigh and transfer it to your left hand.","Push off with your right foot to return to the starting position, while simultaneously passing the kettlebell back to your right hand.","Repeat the lunge on the opposite side, passing the kettlebell under your left thigh.","Continue alternating lunges and passing the kettlebell between hands for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C489C7C1-AFD3-541A-8BD6-96484D7A6734","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C5718EE5-A232-539C-8A4A-244098EB07BD'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"C5718EE5-A232-539C-8A4A-244098EB07BD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Kettlebell One Arm Clean And Jerk","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip.","Bend your knees slightly and hinge at the hips, lowering the kettlebell between your legs.","Explosively extend your hips, knees, and ankles, using the momentum to swing the kettlebell up to shoulder height.","As the kettlebell reaches shoulder height, rotate your wrist and punch your hand straight up, locking out your arm overhead.","Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A558EF56-52AC-5824-8108-80EA25359F1D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('64E792F7-CFA8-5EF8-A694-E15D7E53D960'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"64E792F7-CFA8-5EF8-A694-E15D7E53D960","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Kettlebell One Arm Floor Press","notes":"","plannedSets":3,"proTips":["Lie flat on your back on the floor with your knees bent and feet flat on the ground.","Hold the kettlebell in one hand with your palm facing towards your feet and your arm extended straight up towards the ceiling.","Slowly lower the kettlebell towards your chest by bending your elbow, keeping your upper arm close to your body.","Pause for a moment when the kettlebell is just above your chest, then push it back up to the starting position by extending your elbow.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"121ED5A1-CD34-5129-8913-93B37C13E348","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('51E01BD2-1A9C-58CF-A99C-3DFAD59DD15F'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"51E01BD2-1A9C-58CF-A99C-3DFAD59DD15F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Kettlebell One Arm Jerk","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height.","Bend your knees slightly and engage your core.","Press the kettlebell overhead in a straight line, fully extending your arm.","As you press the kettlebell overhead, simultaneously dip your knees and quickly straighten them to generate momentum.","As the kettlebell reaches its highest point, quickly drop underneath it by bending your knees and hips.","Catch the kettlebell with a slight bend in your knees and hips, and your arm fully extended overhead.","Stand up straight, fully extending your knees and hips, and stabilize the kettlebell overhead.","Lower the kettlebell back to the starting position by bending your knees and hips, and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4E645AF0-4D58-5226-B89F-E9A8512ABD21","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('428DEA18-D608-5AE8-B1A0-3FE9EA718803'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"428DEA18-D608-5AE8-B1A0-3FE9EA718803","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Kettlebell One Arm Military Press To The Side","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height.","Engage your core and keep your back straight.","Press the kettlebell overhead, extending your arm fully.","Pause for a moment at the top, then slowly lower the kettlebell back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C70AA293-C9C5-5E0C-934F-D59628BE11B9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0877BBA7-BFD9-5C66-B2C0-7960C8607005'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"0877BBA7-BFD9-5C66-B2C0-7960C8607005","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Kettlebell One Arm Push Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder level.","Bend your knees slightly and engage your core.","Press the kettlebell overhead by extending your arm and fully extending your legs.","Lower the kettlebell back to the starting position by bending your knees and bringing the kettlebell back to your shoulder.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B193213C-5CFA-57E7-B691-38760ED8ECFB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DFA167CD-D17D-52C1-A116-F63839582B06'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"DFA167CD-D17D-52C1-A116-F63839582B06","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Kettlebell One Arm Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.","Pull the kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the kettlebell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides and repeat with the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B072B7E7-1FE7-5140-9E37-7F8CB6B6A86A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BC80A2C1-DE6C-55CE-B700-245379181557'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"BC80A2C1-DE6C-55CE-B700-245379181557","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Forearms","Core"],"name":"Kettlebell One Arm Snatch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand between your legs.","Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground.","Explosively extend your hips and knees, using the momentum to swing the kettlebell up towards your shoulder.","As the kettlebell reaches shoulder height, rotate your hand and punch it straight up overhead, fully extending your arm.","Lower the kettlebell back down between your legs and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7F6DD5E3-4BD6-5ECD-A733-EC0A679BFB7F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9113D632-D15B-5ACD-914A-B2EF6E678DE2'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"9113D632-D15B-5ACD-914A-B2EF6E678DE2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Forearms"],"name":"Kettlebell Pirate Supper Legs","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise the kettlebell up to shoulder height, keeping your elbow close to your body.","Extend your arm fully overhead, straightening your elbow.","Lower the kettlebell back down to shoulder height, then return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9D93EB0A-0101-5936-90DC-CF805131AE00","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6CB397EF-60E8-569A-AF1E-7D0E58C14313'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Kettlebell","hint":"","id":"6CB397EF-60E8-569A-AF1E-7D0E58C14313","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Kettlebell Pistol Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands.","Lift your left foot off the ground and extend it forward, keeping it parallel to the ground.","Slowly lower your body down into a squat position, keeping your right foot flat on the ground and your left leg extended.","Pause for a moment at the bottom of the squat, then push through your right heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"601C501B-6B93-5EA7-8F7E-547A6C017573","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1330B749-2A60-5AF6-875C-EDCC7018D110'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"1330B749-2A60-5AF6-875C-EDCC7018D110","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Kettlebell Plyo Push-Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands on the kettlebells, shoulder-width apart.","Lower your chest towards the ground, keeping your elbows close to your body.","Push through your hands explosively, lifting your hands off the kettlebells and extending your arms fully.","Land softly back on the kettlebells and immediately lower your chest back down for the next repetition.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A6DDB17A-E6B7-5ECD-B650-867D68D171F8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3367798C-D155-529A-9BBA-4AFA0E2490D8'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"3367798C-D155-529A-9BBA-4AFA0E2490D8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Kettlebell Seated Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a kettlebell in each hand at shoulder height, palms facing forward.","Press the kettlebells overhead, fully extending your arms.","Lower the kettlebells back to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8BE4F5E7-78B6-500B-9441-BFF809E3E7FB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A2EB738E-A3B7-554A-A903-941648CE198C'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"A2EB738E-A3B7-554A-A903-941648CE198C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Kettlebell Seated Two Arm Military Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a kettlebell in each hand at shoulder level with your palms facing forward.","Press the kettlebells overhead by extending your arms fully.","Pause for a moment at the top, then slowly lower the kettlebells back to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B025FD1C-67E0-50A8-BF55-00DBAD97DABA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('97489118-7FB7-570B-A046-FB98388F7B2C'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"97489118-7FB7-570B-A046-FB98388F7B2C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Kettlebell Seesaw Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.","Press one kettlebell overhead while keeping the other kettlebell at shoulder height.","Lower the pressed kettlebell back to shoulder height while simultaneously pressing the other kettlebell overhead.","Continue alternating the pressing motion, creating a seesaw-like movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"79E78ADC-D4BA-5E94-BF77-E033FCC4549B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3692F1B0-73DF-54BF-A7A9-5EE8D4337D57'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"3692F1B0-73DF-54BF-A7A9-5EE8D4337D57","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders","Glutes","Hamstrings"],"name":"Kettlebell Sumo High Pull","notes":"","plannedSets":3,"proTips":["Stand with your feet wider than shoulder-width apart, toes pointing outwards.","Hold a kettlebell with both hands in front of your body, arms extended downwards.","Bend your knees and lower your hips into a squat position, keeping your back straight.","Drive through your heels and explosively extend your hips and knees, pulling the kettlebell up towards your chin.","As you pull the kettlebell up, keep your elbows high and wide, and squeeze your shoulder blades together.","Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1F37376F-399C-5DF8-BC80-876390092B54","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('66F927B4-B7BD-57E1-B30E-53DA5136A80A'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"66F927B4-B7BD-57E1-B30E-53DA5136A80A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Core"],"name":"Kettlebell Swing","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes pointed slightly outward.","Hold the kettlebell with both hands in front of your body, arms extended.","Bend your knees slightly and hinge at the hips, pushing your butt back.","Swing the kettlebell back between your legs, keeping your arms straight and maintaining a flat back.","Drive your hips forward and swing the kettlebell up to shoulder height, using the momentum generated by your hips.","Allow the kettlebell to swing back down between your legs and repeat the movement for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"67056CF8-878F-54DC-BF43-DAC95127B175","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('782CDA63-6DE3-5A5D-AFAB-B70E0607E958'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"782CDA63-6DE3-5A5D-AFAB-B70E0607E958","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Quadriceps","Glutes","Core"],"name":"Kettlebell Thruster","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands, palms facing each other.","Lower into a squat position by bending your knees and pushing your hips back, keeping your chest up and your back straight.","As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the kettlebell overhead.","Lock out your arms at the top of the movement, fully extending your elbows.","Lower the kettlebell back to the starting position by reversing the movement, bending your elbows and lowering the weight back to your chest.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"85859A89-C888-53DA-A89C-F1ED24B68CAE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('56AED3DD-2C19-503E-A32D-4238D82AD45E'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Kettlebell","hint":"","id":"56AED3DD-2C19-503E-A32D-4238D82AD45E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Core"],"name":"Kettlebell Turkish Get Up (Squat Style)","notes":"","plannedSets":3,"proTips":["Start by lying on your back with your legs extended and the kettlebell held in your right hand, arm fully extended above your shoulder.","Bend your right knee and place your right foot flat on the ground, keeping your left leg extended.","Pressing through your right foot, lift your hips off the ground, coming into a bridge position.","Slide your left leg underneath your body, bending your left knee and placing your left foot flat on the ground.","Rotate your torso to the left, bringing your left hand to the ground for support.","Pressing through your right foot and left hand, lift your torso off the ground, coming into a kneeling position.","From the kneeling position, stand up, keeping the kettlebell extended overhead.","Reverse the movement to return to the starting position.","Repeat the exercise on the other side, starting with the kettlebell in your left hand."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"58D08B2F-CC5B-5687-8033-A98564F58CC8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F6F9A2E8-0E56-5115-8A1D-C41388D28DD7'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"F6F9A2E8-0E56-5115-8A1D-C41388D28DD7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Forearms"],"name":"Kettlebell Two Arm Clean","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs with both hands, palms facing towards you.","Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground.","Explosively extend your hips and knees, using the momentum to pull the kettlebell up towards your shoulders.","As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbows tucked in and the kettlebell resting on the back of your forearm.","Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7710B633-9DF0-55DA-B442-D2D443A75F17","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2117E2CB-0679-5061-A02F-DB3A5B74252B'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"2117E2CB-0679-5061-A02F-DB3A5B74252B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Kettlebell Two Arm Military Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder level with your palms facing forward.","Engage your core and press the kettlebells overhead, fully extending your arms.","Pause for a moment at the top, then slowly lower the kettlebells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BD12D903-C037-543D-AE3D-749494202920","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7D0874D4-F26C-59B8-A3F6-D110634EAF40'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"7D0874D4-F26C-59B8-A3F6-D110634EAF40","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Kettlebell Two Arm Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the kettlebells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the kettlebells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"35BDFCFC-6DC7-56CD-9C2B-0E6936F17F5C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5384C532-AD98-5290-94C8-70F04F639FFF'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Kettlebell","hint":"","id":"5384C532-AD98-5290-94C8-70F04F639FFF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Shoulders"],"name":"Kettlebell Windmill","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a kettlebell in your right hand overhead.","Rotate your left foot outwards about 45 degrees and keep your right foot pointing forward.","Bend your torso to the left side, keeping your right arm extended overhead and your eyes on the kettlebell.","Lower your torso as far as you can while keeping your right arm straight and your left arm extended to the side.","Pause for a moment, then return to the starting position by pushing through your right foot and engaging your obliques.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"821A28A6-E73B-5DD3-8E0D-08A04FACA988","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C2376396-FC32-5D6C-8447-6320127EA27D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C2376396-FC32-5D6C-8447-6320127EA27D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Quadriceps","Glutes"],"name":"Kick Out Sit","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench or chair with your feet flat on the ground and your knees bent at a 90-degree angle.","Lean back slightly and place your hands on the edge of the bench or chair for support.","Engaging your hamstrings, lift your feet off the ground and extend your legs straight out in front of you.","Pause for a moment at the top, then slowly bend your knees and bring your feet back towards your body.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FD01E0C7-ED43-51C0-A90F-825C655D66D6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('61EB8144-5E06-51E6-A1E7-91AA2C2A20F4'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"61EB8144-5E06-51E6-A1E7-91AA2C2A20F4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Triceps","Shoulders","Core"],"name":"Kipping Muscle Up","notes":"","plannedSets":3,"proTips":["Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Engage your core and use a swinging motion to generate momentum.","As you swing forward, pull your chest towards the bar, using your lats and biceps to initiate the movement.","Continue the upward motion until your chest reaches the bar, then transition into a dip position by pushing down on the bar and extending your arms.","Lower yourself back down to the starting position by bending your arms and controlling the descent.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"41B644ED-F0CA-5CA4-B8E1-41CDF61D7CF8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9358E9AF-B0E3-5FBE-8886-8D8BC840E145'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9358E9AF-B0E3-5FBE-8886-8D8BC840E145","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Knee Touch Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your shoulder blades off the ground and reach your right hand towards your left knee.","Return to the starting position and repeat, this time reaching your left hand towards your right knee.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A46A4F02-F2C6-526F-8C88-5D5DD179D22B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('60AADD9C-580E-5D82-B5FA-49EC08EF0C0B'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"60AADD9C-580E-5D82-B5FA-49EC08EF0C0B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Kneeling Jump Squat","notes":"","plannedSets":3,"proTips":["Start by kneeling on the ground with your feet hip-width apart and your toes pointing forward.","Hold a barbell across your upper back, resting it on your shoulders.","Engage your core and glutes, then explosively jump up into the air, extending your hips and knees.","As you jump, push through your toes and fully extend your ankles, knees, and hips.","Land softly back on the ground, bending your knees to absorb the impact.","Immediately go into the next repetition, repeating the jump squat motion."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E76B6046-5B18-5C6D-BD08-4C17748160ED","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"C839920F-7F0E-57FE-BFE4-55ABBD99141A","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"80566C56-792B-59B5-A496-9366C653BED1","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"7AF17EE2-E716-5268-8DE0-3D4A70B94438","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D2E33093-D73A-5CAA-A2E0-3779184CAEAC'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D2E33093-D73A-5CAA-A2E0-3779184CAEAC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Triceps"],"name":"Kneeling Lat Stretch","notes":"","plannedSets":3,"proTips":["Kneel on the ground with your knees hip-width apart and your toes pointing back.","Extend your arms overhead and interlace your fingers.","Keeping your back straight, slowly lean to the right side, feeling a stretch in your left lat muscle.","Hold the stretch for 20-30 seconds, then return to the starting position.","Repeat the stretch on the left side, leaning to the left and feeling a stretch in your right lat muscle.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"47ED869C-E23E-56D1-873E-185DA1B2050B","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('E9C294BE-2E06-5B79-AF92-4AE4F71735E5'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E9C294BE-2E06-5B79-AF92-4AE4F71735E5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Triceps"],"name":"Kneeling Plank Tap Shoulder","notes":"","plannedSets":3,"proTips":["Start in a kneeling position with your hands on the ground, shoulder-width apart.","Extend your legs behind you, resting on your toes, and lift your body into a plank position.","Keeping your core engaged and your hips stable, lift one hand off the ground and tap the opposite shoulder.","Return the hand to the ground and repeat with the other hand.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"12C33D03-6FA4-59EA-B85C-85380F38581B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7B959A44-2507-5950-B3BA-A59C6DD00B84'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"7B959A44-2507-5950-B3BA-A59C6DD00B84","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Kneeling Push-Up","notes":"","plannedSets":3,"proTips":["Start by kneeling on the ground with your hands shoulder-width apart, fingers pointing forward.","Extend your legs behind you, resting on the balls of your feet, so that your body forms a straight line from head to heels.","Engage your core and lower your body towards the ground by bending your elbows, keeping them close to your sides.","Continue lowering until your chest is just above the ground, then push back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"76F94878-8F12-5C67-8DF1-FF015D749934","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('05D499C1-A9E6-554F-B812-94A23224ACCF'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"05D499C1-A9E6-554F-B812-94A23224ACCF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Korean Dips","notes":"","plannedSets":3,"proTips":["Position yourself between two parallel bars with your arms extended and supporting your body weight.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E87C12BA-2004-5BA5-90F0-FD7BE3BD1032","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3D5A4CB7-1AA4-5E69-8461-6C518A422E1C'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3D5A4CB7-1AA4-5E69-8461-6C518A422E1C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"L-Pull-Up","notes":"","plannedSets":3,"proTips":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your body straight.","Engage your lats and biceps to pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"599E1846-65A8-5593-ABC4-A9DF7C1DF8CC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CA7DCAA6-D17E-5F34-B2B7-BDC2C852A22B'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CA7DCAA6-D17E-5F34-B2B7-BDC2C852A22B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"L-Sit On Floor","notes":"","plannedSets":3,"proTips":["Sit on the floor with your legs extended in front of you.","Place your hands on the floor beside your hips, fingers pointing forward.","Engage your core and lift your legs off the ground, keeping them straight.","Try to bring your legs parallel to the floor, forming an ''L'' shape with your body.","Hold this position for as long as you can.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0A752AE5-613B-5943-A268-A1F6102286E3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CC282FE3-2342-56C0-8070-76E7783AB4F1'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"CC282FE3-2342-56C0-8070-76E7783AB4F1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Quadriceps"],"name":"Landmine 180","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the barbell with both hands in front of your chest.","Bend your knees slightly and rotate your torso to the right, swinging the barbell down towards your right hip.","As you reach the bottom of the movement, quickly reverse the motion and rotate your torso to the left, swinging the barbell up and across your body towards your left shoulder.","Continue this twisting motion, alternating sides, for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"EC9B0022-AD9F-5BA2-8227-CE9713B9A6A2","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"6A01C52D-B86A-50C4-950E-056943EBFF91","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"28EF9796-996C-5B90-9F59-72495223CF16","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"99EAA431-88C2-5D0F-BD09-C6DE922465CA","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('096F0FD8-261C-5898-96FB-26DCE585D63C'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"096F0FD8-261C-5898-96FB-26DCE585D63C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Upper Back"],"name":"Landmine Lateral Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the barbell with an overhand grip, resting it on the front of your shoulders.","Keeping your core engaged and back straight, lift the barbell up and away from your body, raising it to shoulder height.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A73D15BF-FD12-55EC-BD44-108207870686","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"25F69E51-B355-5861-A038-C97DFEC8EC41","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B5C5D3F9-1A3D-50EE-83FE-55C6E79D6129","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"732F1027-6476-55C4-9D9C-C788BB89B1E3","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5A1F6609-705D-5F15-BB39-36FCCC1888DA'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"5A1F6609-705D-5F15-BB39-36FCCC1888DA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Chest","Triceps"],"name":"Lean Planche","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands shoulder-width apart and your body straight.","Engage your core and slowly shift your weight forward, bringing your shoulders past your hands.","Keep your elbows slightly bent and your body straight as you lean forward.","Hold this position for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D7CB6A42-8D6A-5FAE-B459-6FDFCF91C2FB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3190F4B0-9141-5FA4-9E8F-2872B61DAA1E'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3190F4B0-9141-5FA4-9E8F-2872B61DAA1E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Biceps","Triceps","Forearms"],"name":"Left Hook. Boxing","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Keep your left hand up to protect your face and your right hand by your chin.","Rotate your hips and pivot on your left foot as you extend your left arm forward in a punching motion.","Twist your torso and engage your core muscles to generate power in the punch.","Snap your arm back to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"75302950-C15D-5C51-8238-3C299EFFC2E2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D9E7FEB3-6A24-5CF2-B2BB-5F2D247F3A31'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D9E7FEB3-6A24-5CF2-B2BB-5F2D247F3A31","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Leg Pull In Flat Bench","notes":"","plannedSets":3,"proTips":["Sit on a flat bench with your legs extended straight out in front of you.","Place your hands on the bench beside your hips for support.","Engage your abs and lift your legs off the ground, bringing your knees towards your chest.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F10CDCDE-ABDC-59A3-BAF0-7938DA20DF8F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1FF01785-1A41-579D-8BAD-6F5BF9A129FE'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1FF01785-1A41-579D-8BAD-6F5BF9A129FE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes"],"name":"Leg Up Hamstring Stretch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended.","Bend one knee and bring it towards your chest, holding onto your thigh or shin.","Straighten your leg as much as possible while keeping it elevated.","Hold the stretch for 20-30 seconds.","Repeat with the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"494F173A-B17B-5926-BCD8-0F2128BB0CE5","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('A3E6B449-CF10-513E-B64D-CDAD543830A3'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"A3E6B449-CF10-513E-B64D-CDAD543830A3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Glutes"],"name":"Lever Alternate Leg Press","notes":"","plannedSets":3,"proTips":["Adjust the seat and foot platform of the leverage machine to your desired position.","Sit on the machine with your back against the backrest and your feet on the foot platform.","Place your hands on the handles or sides of the machine for stability.","Push one foot against the foot platform, extending your leg until it is almost fully straight.","Pause for a moment, then slowly bend your leg and return to the starting position.","Repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"495B9C74-4A34-55BD-B163-85C6244B9889","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"25FEED0D-560E-5D22-ACD9-A50D9F21AE8F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('817687D1-D3D0-5188-9F3E-1475CF73FB9F'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"817687D1-D3D0-5188-9F3E-1475CF73FB9F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever Alternating Narrow Grip Seated Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and footplate position to ensure proper alignment.","Sit on the machine with your back straight and feet flat on the footplate.","Grasp the handles with a narrow grip, palms facing each other.","Keep your chest up and shoulders back throughout the exercise.","Pull one handle towards your torso while keeping the other handle stationary.","Squeeze your shoulder blades together at the end of the movement.","Slowly return the handle to the starting position and repeat with the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"30DD35D7-A193-5E87-B35F-1531724F3CEA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"0B251542-04A9-5CCB-8668-E8D5437B1BB2","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('ACD298F6-D93E-50D5-BDC2-9F3EECCFF9C2'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"ACD298F6-D93E-50D5-BDC2-9F3EECCFF9C2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Lever Assisted Chin-Up","notes":"","plannedSets":3,"proTips":["Adjust the leverage machine to your desired resistance level.","Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended, keeping your body straight.","Engage your back muscles and pull your body up towards the handles, leading with your chest.","Continue pulling until your chin is above the handles.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"750BC171-5684-5A37-B7C7-5DC56B7ACFC4","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"FD55BC6A-DDE1-58F5-B36D-683AC83DC3C8","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CC51774B-BC23-5337-8D84-B3E38499AFC7'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"CC51774B-BC23-5337-8D84-B3E38499AFC7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Lever Back Extension","notes":"","plannedSets":3,"proTips":["Adjust the machine to fit your body size and range of motion.","Sit on the machine with your back against the pad and your feet secured.","Place your hands on the handles or grip bars.","Engage your core and slowly lean forward, allowing your back to round slightly.","Pause for a moment at the bottom position, feeling a stretch in your lower back.","Using your back muscles, slowly raise your torso back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"FD7B954A-C410-58ED-B561-BEE413254190","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"7C9A1748-3334-509D-9B1F-3EEB344AC778","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('38CD3DEF-C9AD-5D4E-9ACE-0948C16A8744'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"38CD3DEF-C9AD-5D4E-9ACE-0948C16A8744","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever Bent Over Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up.","Pull the barbell towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"8BADCBC2-9544-5317-993A-A89B0951A85D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"DB359C20-A545-579E-BF3C-C0245E3A5BF9","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"903F4540-E48D-50D8-97E3-2192B5150090","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"0704C9DC-2279-56BA-9F02-33D074318529","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9C4C5B5B-81CE-5D08-B75D-6A1EC6EE79BF'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"9C4C5B5B-81CE-5D08-B75D-6A1EC6EE79BF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever Bent-Over Row With V-Bar","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself facing the machine.","Grasp the v-bar with an overhand grip, keeping your back straight and your knees slightly bent.","Pull the v-bar towards your abdomen, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the weight back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"C658A92A-D11D-5685-8B58-3D0CFC043520","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C39B5151-DAA8-5462-9F37-BC89397AC71F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C476F237-12E4-59D9-871F-34C06B4FE748'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"C476F237-12E4-59D9-871F-34C06B4FE748","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Lever Bicep Curl","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles with an underhand grip, palms facing up, and keep your elbows close to your sides.","Exhale and curl the handles upward, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"8C4BCF1C-BD9B-5B0D-B770-0EEB2C0613ED","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D35AA980-2ADC-5EE3-85C4-12082F22DC72","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D893F552-C292-525C-8BA5-C66E71FCDCC9'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"D893F552-C292-525C-8BA5-C66E71FCDCC9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Lever Calf Press","notes":"","plannedSets":3,"proTips":["Adjust the seat of the leverage machine so that your shoulders are aligned with the lever pad.","Place your toes on the lever pad, with your heels hanging off the edge.","Grasp the handles or side supports for stability.","Push the lever pad down by extending your ankles, contracting your calf muscles.","Pause for a moment at the bottom of the movement.","Slowly return to the starting position by allowing your heels to rise back up.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"EA27B590-7762-5459-B026-8B6A0FA85432","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"68BB7EB3-FBC1-51AC-AD4F-26B5164863AF","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EEE84347-C3D3-5935-BC5F-BEC0613C5CC0'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Machine","hint":"","id":"EEE84347-C3D3-5935-BC5F-BEC0613C5CC0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Lever Chest Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back flat against the pad.","Grasp the handles with an overhand grip and position your elbows at a 90-degree angle.","Push the handles forward until your arms are fully extended, exhaling during the movement.","Pause briefly at the end of the movement, then slowly return to the starting position, inhaling as you do so.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"42FEAF35-E60E-5612-B888-79AAE0B9272B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"63537F0B-52E7-53A9-AF62-BF8EB778E5A7","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('27702009-2AAF-591E-94EE-F2954B76FD70'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Machine","hint":"","id":"27702009-2AAF-591E-94EE-F2954B76FD70","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Lever Deadlift","notes":"","plannedSets":3,"proTips":["Adjust the seat height and foot platform to your desired position.","Sit on the machine with your back against the pad and your feet flat on the foot platform.","Grasp the handles or the sides of the seat for stability.","Engage your glutes and hamstrings, and push through your heels to lift the weight up.","Keep your back straight and avoid rounding your shoulders.","Extend your hips fully at the top of the movement, squeezing your glutes.","Lower the weight back down in a controlled manner, keeping tension on your glutes and hamstrings.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"A49E5107-BC5B-52AF-B2F0-13CF3D813B16","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4B94142F-FBF6-5061-B436-6555FE3A61A4","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1D4C5FC5-E99B-5AC8-AEE8-C222FEAF41D7'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Machine","hint":"","id":"1D4C5FC5-E99B-5AC8-AEE8-C222FEAF41D7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Lever Decline Chest Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and backrest of the leverage machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet flat on the floor.","Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.","Push the handles forward and away from your body until your arms are fully extended.","Slowly lower the handles back towards your chest, keeping your elbows slightly bent.","Pause for a moment at the bottom, then push the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"E5291242-C8F8-5856-88C1-62D714489CD0","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4157B451-7265-5B62-AEF4-FC867FC21BCA","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('45DEDA1F-D481-5E28-9A6D-874B6F492B87'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"45DEDA1F-D481-5E28-9A6D-874B6F492B87","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Lever Donkey Calf Raise","notes":"","plannedSets":3,"proTips":["Adjust the leverage machine to the appropriate height for your body.","Position yourself facing the machine, with your toes on the foot platform and your heels hanging off the edge.","Place your hands on the handles or the support bars for stability.","Engage your calves and lift your heels as high as possible, using the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"72FAFA82-E5A0-5D08-A74D-B7B825A876CD","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"47C7801D-C69E-5821-ACB2-EF7C2EDDBB2C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('990DF9DA-672D-559E-8855-F98ABC557FF0'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"990DF9DA-672D-559E-8855-F98ABC557FF0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Lever Front Pulldown","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Sit upright with your chest lifted and your shoulders back, maintaining a slight arch in your lower back.","Engage your lats and pull the handles down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"859B0A5E-746F-5C76-8BFA-6B5E62E8EE89","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"CEADF737-CB91-5592-8B06-47165B9392A7","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('69FF023A-52F4-5B0D-9625-B0DB1B002B09'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"69FF023A-52F4-5B0D-9625-B0DB1B002B09","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders","Forearms"],"name":"Lever Gripless Shrug","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the leverage machine.","Grasp the handles with your palms facing inwards and your arms fully extended.","Keeping your back straight, exhale and elevate your shoulders as high as possible.","Hold the contraction for a brief moment, then inhale and slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B2200BF2-AB18-5420-86E7-6D0EE656B8C5","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"02B6927D-87BB-530B-9EB1-759B793D1CCC","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5C6726E7-69E3-5233-B319-1E871CFF9AC9'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"5C6726E7-69E3-5233-B319-1E871CFF9AC9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders","Forearms"],"name":"Lever Gripless Shrug V. 2","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles or bars with an overhand grip, keeping your arms straight.","Keeping your back straight, lift your shoulders up towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D1A5DD84-FF81-5148-9032-CE94C22FA499","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"31A78DB4-AD29-5D2D-9B7A-4AE42370A61E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('80D5A621-F775-5286-A416-C1ADF949FDAD'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"80D5A621-F775-5286-A416-C1ADF949FDAD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Triceps"],"name":"Lever Gripper Hands","notes":"","plannedSets":3,"proTips":["Adjust the seat height and grip the handles of the leverage machine.","Keep your back straight and your feet flat on the ground.","Exhale and squeeze the handles, contracting your forearms.","Hold the contraction for a second, then slowly release and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"2968C955-44BF-5503-BA86-D997A46D68DC","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"92D086F5-0E08-5E48-9074-84068BA52C04","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('446BE59E-2BE7-51FC-ACF7-EA9D9953533F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"446BE59E-2BE7-51FC-ACF7-EA9D9953533F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Lever Hammer Grip Preacher Curl","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the leverage machine.","Place your upper arms on the preacher pad, ensuring your chest is pressed against it.","Grasp the handles with a hammer grip (palms facing each other).","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"FF15E743-C20E-51D6-B8A4-23AA4C73F2FF","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D343C98E-E10C-5FD9-9177-61DEE20F3FA5","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EBD3B2DE-B5F7-5BE6-BFEA-45AE5A314CE6'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"EBD3B2DE-B5F7-5BE6-BFEA-45AE5A314CE6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Rear Deltoids"],"name":"Lever High Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and foot platform to a comfortable position.","Sit on the machine with your chest against the pad and your feet flat on the foot platform.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and engage your core.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"4B37F451-165B-5312-90EC-9535F80564C5","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3FADEEFC-1FDE-5C7C-86EE-B427EE1B3D14","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('86B3FC65-8639-5AA4-BF40-69BAFD49CE74'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"86B3FC65-8639-5AA4-BF40-69BAFD49CE74","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings"],"name":"Lever Hip Extension V. 2","notes":"","plannedSets":3,"proTips":["Adjust the machine to fit your body and sit on it with your back against the backrest.","Place your feet on the footrests and grip the handles for stability.","Engage your glutes and hamstrings, then push against the footrests to extend your hips and raise your legs backward.","Pause for a moment at the top, then slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"19B758BA-1623-5C3F-A213-947033D550FF","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"DA14ACBB-B854-5A00-9E03-3D1E5DD09F37","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A0DEE30F-0ACD-5F21-B9D5-E4B7BC6C5030'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"A0DEE30F-0ACD-5F21-B9D5-E4B7BC6C5030","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Lever Horizontal One Leg Press","notes":"","plannedSets":3,"proTips":["Adjust the seat of the machine so that your knees are at a 90-degree angle when your feet are on the footplate.","Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate.","Place your hands on the handles or sides of the machine for stability.","Push the footplate away from your body by extending your leg, keeping your back against the backrest.","Pause for a moment at the fully extended position, then slowly bend your leg to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"89126B5E-F64B-5A36-951F-EA18AD52AC23","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3EB10C8B-788A-5EA6-A6BB-22A550F3A4D9","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('30E2F4DB-5980-5FF7-82F5-15CA00EE97D6'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Machine","hint":"","id":"30E2F4DB-5980-5FF7-82F5-15CA00EE97D6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Lever Incline Chest Press","notes":"","plannedSets":3,"proTips":["Adjust the seat and backrest of the leverage machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet flat on the floor.","Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.","Push the handles forward and away from your body until your arms are fully extended.","Pause for a moment, then slowly bend your elbows and lower the handles back towards your chest.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"74511DCF-3308-5C1F-8238-4D0F6F33EEBE","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"74619D2C-D138-545C-A559-52DB82EDCF7E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('42430DF6-5131-52E9-BF54-A26C28E26810'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Machine","hint":"","id":"42430DF6-5131-52E9-BF54-A26C28E26810","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Lever Incline Chest Press V. 2","notes":"","plannedSets":3,"proTips":["Adjust the seat height and backrest angle on the leverage machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet flat on the floor.","Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.","Push the handles forward and away from your body until your arms are fully extended, but without locking your elbows.","Pause for a moment at the fully extended position, then slowly bend your elbows and lower the handles back towards your chest.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"5DC48BC3-0B81-5ED6-B08E-1901AB6387E1","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C7147188-5594-5BA3-BED3-4735C6347912","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('91D81817-2FCC-5E5B-9328-06C680D4FBE3'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"91D81817-2FCC-5E5B-9328-06C680D4FBE3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes"],"name":"Lever Kneeling Leg Curl","notes":"","plannedSets":3,"proTips":["Adjust the machine to fit your body and select the desired weight.","Kneel on the machine facing downwards, with your knees resting on the pad and your feet secured under the footpads.","Grasp the handles or the sides of the machine for stability.","Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees.","Pause for a moment at the top of the movement, squeezing your hamstrings.","Inhale and slowly lower your legs back to the starting position, fully extending your knees.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1C04D233-19C5-5D02-9F2A-86D74EEC2F0F","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"5C2C44D6-242D-53FD-8FDB-1AE59958A800","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0DB5E441-FD08-5A28-BABA-57C714441890'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Machine","hint":"","id":"0DB5E441-FD08-5A28-BABA-57C714441890","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Lever Kneeling Twist","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your knees resting on the pads and your upper body facing forward.","Grasp the handles or the sides of the machine for stability.","Keeping your core engaged, twist your torso to one side as far as comfortably possible.","Pause for a moment, then slowly return to the starting position.","Repeat the twist to the opposite side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"59109233-04A5-58D9-92CA-3179ED1DA748","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4C0265F2-C765-533B-AD27-BAEAB6E86A9B","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1ACE603D-6C19-5B78-AE08-A31741FBF628'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Machine","hint":"","id":"1ACE603D-6C19-5B78-AE08-A31741FBF628","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Upper Back"],"name":"Lever Lateral Raise","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles with an overhand grip and keep your arms straight.","Exhale and raise your arms out to the sides until they are parallel to the floor.","Pause for a moment at the top, then inhale and slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"92FC5AD2-41CD-5D07-8ED4-DC596E496A62","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"59107C9D-E361-5396-92DD-BC43CC8A5AA6","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('28C5021A-773E-5A0C-B54A-A6174EC850A6'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"28C5021A-773E-5A0C-B54A-A6174EC850A6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings"],"name":"Lever Leg Extension","notes":"","plannedSets":3,"proTips":["Adjust the seat height and backrest of the machine to fit your body.","Sit on the machine with your back against the backrest and your feet on the footpad.","Grasp the handles or sidebars for stability.","Extend your legs forward by straightening your knees, lifting the weight.","Pause for a moment at the top, then slowly lower the weight back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"E595A224-DFF1-5AE4-BB60-67CB20BC590A","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"E46B11FE-C716-57F1-9790-A088A36F2F1A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BB0F043C-F67F-5901-9040-8D7FF80968FC'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"BB0F043C-F67F-5901-9040-8D7FF80968FC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Calves"],"name":"Lever Lying Leg Curl","notes":"","plannedSets":3,"proTips":["Adjust the machine to fit your body and select the desired weight.","Lie face down on the machine with your legs straight and your heels against the padded lever.","Grasp the handles or the sides of the machine for stability.","Keeping your upper body stationary, exhale and curl your legs up as far as possible without lifting your hips off the pad.","Hold the contracted position for a brief pause as you squeeze your hamstrings.","Inhale and slowly lower the lever back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"E494B6E3-226C-5247-A7CD-7F006F220EDF","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4A160924-CE21-583C-A067-D886BEBC6F5B","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AFF38D22-853A-5F6F-A60B-8E088E4A90D8'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"AFF38D22-853A-5F6F-A60B-8E088E4A90D8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes"],"name":"Lever Lying Two-One Leg Curl","notes":"","plannedSets":3,"proTips":["Adjust the machine to fit your body and sit on it with your back against the backrest.","Place your legs on the lever pad, just above your ankles.","Grasp the handles on the sides of the machine for support.","Keeping your upper body still, exhale and curl your legs up towards your glutes.","Pause for a moment at the top, then inhale and slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"3C64B84E-AF6C-5BDD-BB36-9CAAE034B3FA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"8974A48E-6260-5684-9E60-35926456860E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0A0E5561-FB90-5EF3-AE38-52189D18318E'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Machine","hint":"","id":"0A0E5561-FB90-5EF3-AE38-52189D18318E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Chest"],"name":"Lever Military Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back against the backrest.","Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.","Push the handles upward until your arms are fully extended, but do not lock your elbows.","Pause for a moment at the top, then slowly lower the handles back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"4BDB0A65-EF67-5933-B133-9D53BF3E0C02","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C006248C-BB78-5993-B436-06CAEA5FB4E3","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('652ADD85-3F44-5FB5-8C4C-FA9B1DA97304'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"652ADD85-3F44-5FB5-8C4C-FA9B1DA97304","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever Narrow Grip Seated Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and footrests to ensure proper form.","Sit on the machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handles with a narrow grip, palms facing each other.","Keep your back straight and lean slightly forward.","Pull the handles towards your torso, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement.","Slowly release the handles and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"8448DF36-23D9-5B4F-8A99-EBD834E3488C","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"7D07E79A-1530-544E-831F-0D5D07719A60","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('ED93925C-DBB6-5C42-9411-AB6344E3D08C'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"ED93925C-DBB6-5C42-9411-AB6344E3D08C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever One Arm Bent Over Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with an overhand grip.","Bend forward at the hips, keeping your back straight and your head up.","Let the barbell hang in front of you with your arms fully extended.","Pull the barbell up towards your chest, keeping your elbows close to your body.","Squeeze your shoulder blades together at the top of the movement.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"6F24FB8B-2E99-5640-8561-3DEBD054E290","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"06BF63D1-D515-5700-A810-69A1B8F1FC4B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"1398892F-F201-5413-94BE-350BD85EC763","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3344D0F3-F9AE-53BA-9FAD-F109C370E0CB","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3B210FF9-DEA0-58D3-A869-D8E09C194120'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"3B210FF9-DEA0-58D3-A869-D8E09C194120","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Lever One Arm Lateral High Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself facing the machine.","Grasp the handle with one hand and keep your back straight.","Pull the handle towards your body, keeping your elbow close to your side.","Squeeze your back muscles at the top of the movement.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"9FE13248-7D14-57DA-9DE2-83ECD5603232","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C88C1F43-D4E1-51CA-83C9-8935888FE7C7","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C2D8A757-CAAA-571D-9386-3ECD2573FBBB'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"C2D8A757-CAAA-571D-9386-3ECD2573FBBB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Lever One Arm Lateral Wide Pulldown","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.","Grasp the handle with an overhand grip and fully extend your arm, keeping a slight bend in your elbow.","Pull the handle down and across your body towards your opposite hip, squeezing your lat muscle at the bottom of the movement.","Slowly return the handle to the starting position, fully extending your arm.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B38496B0-5BBB-57A0-9256-37B9C9E9E71A","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"EACE7241-25EE-51DF-86A8-0718F630ABBC","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2C2CAA15-44E5-5112-9375-A37EA0AEEA23'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Machine","hint":"","id":"2C2CAA15-44E5-5112-9375-A37EA0AEEA23","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Lever One Arm Shoulder Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the lever handle with one hand and position your elbow at a 90-degree angle.","Press the lever upward until your arm is fully extended overhead.","Pause for a moment at the top, then slowly lower the lever back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"ACFE9F3C-6584-58E5-90F9-01E137C26A84","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D1D2A9D8-16F1-5B61-826F-49C722E0E82F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3B82867F-FF0D-5098-AD68-4E72ED262DFC'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"3B82867F-FF0D-5098-AD68-4E72ED262DFC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Lever Overhand Triceps Dip","notes":"","plannedSets":3,"proTips":["Adjust the machine to the appropriate height and secure your body in position.","Grasp the handles with an overhand grip and position your body so that your arms are fully extended.","Lower your body by bending your elbows, keeping your upper arms close to your sides.","Continue lowering until your upper arms are parallel to the floor.","Pause for a moment, then push yourself back up to the starting position by extending your elbows.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"9A834B3C-D6D8-512C-93E7-B5B89700A17A","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"92E3899F-F4FB-5CFF-92AC-17795F3842F8","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EBC75E08-3FA2-58CF-9541-D523732C626B'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"EBC75E08-3FA2-58CF-9541-D523732C626B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Lever Preacher Curl","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the leverage machine.","Place your upper arms on the pad and grip the handles with an underhand grip.","Keep your back straight and your elbows positioned on the pad.","Exhale and curl your forearms towards your upper arms, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1EE8A317-6D99-5521-B33F-E2F7A3F42DE9","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"A42936A3-D780-51A8-8996-6092D71B6A58","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9C370D68-137F-549C-8220-D4EA34C7B0C1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"9C370D68-137F-549C-8220-D4EA34C7B0C1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Lever Preacher Curl V. 2","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your upper arms resting on the pad and your chest against the support.","Grasp the handles with an underhand grip, slightly wider than shoulder-width apart.","Keep your upper arms stationary and exhale as you curl the handles towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale as you slowly lower the handles back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6FBD357E-F964-5ED1-84AA-2222A37CE0A2","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B83F6CB5-59A3-5EFB-86A7-8F012758E43B","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9872D7EB-2C9F-5EA8-B1D1-F332BC6B147E'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"9872D7EB-2C9F-5EA8-B1D1-F332BC6B147E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Triceps","Shoulders"],"name":"Lever Pullover","notes":"","plannedSets":3,"proTips":["Adjust the seat and handles of the leverage machine to a comfortable position.","Sit on the machine with your back against the pad and grasp the handles with an overhand grip.","Keep your arms slightly bent and your core engaged.","Slowly pull the handles towards your chest, squeezing your lats.","Pause for a moment at the peak contraction, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"4855596D-83CA-58FC-9CAF-0B5076B0E055","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"478F0A8F-21A6-5AE4-8098-1C90AA5D62AA","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FB47327B-03A7-5EBE-805B-DDB55B0B43AA'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"FB47327B-03A7-5EBE-805B-DDB55B0B43AA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Lever Reverse Grip Lateral Pulldown","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back.","Pull the handles down towards your chest, leading with your elbows and squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"404A2CC8-8557-5313-9D9C-CB740CC8CDAD","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B925CF6E-F358-528E-909B-46ABCAF18ED7","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8ED022E6-B732-5C49-B318-BA5DA6A8731A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"8ED022E6-B732-5C49-B318-BA5DA6A8731A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Lever Reverse Grip Preacher Curl","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the leverage machine.","Grasp the handles with an underhand grip, palms facing up.","Rest your upper arms on the preacher pad, ensuring your elbows are fully extended.","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your elbows.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"85611C30-A60F-529B-93AF-15B9963D4556","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1B940CF5-D1A3-5207-84D7-032F9A5D5289","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D0700AD0-B620-5E48-8FBA-6D58C792BF06'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"D0700AD0-B620-5E48-8FBA-6D58C792BF06","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever Reverse Grip Vertical Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and footplate position to ensure proper alignment.","Sit on the machine with your chest against the pad and your feet flat on the footplate.","Grasp the handles with an underhand grip, palms facing up.","Keep your back straight and engage your core.","Pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"E4B2CB18-9E04-590A-9D25-EBADEAE79D58","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"9CB36A46-ABEF-5AC7-BEB0-570F0AAAFE79","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('18253B95-CEF3-5A28-B955-FACDE15E300F'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"18253B95-CEF3-5A28-B955-FACDE15E300F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Lever Reverse Hyperextension","notes":"","plannedSets":3,"proTips":["Adjust the leverage machine to fit your body and secure your feet in the foot pads.","Lie face down on the machine with your upper body hanging off the edge and your hips resting on the pad.","Cross your arms over your chest or place them behind your head.","Engage your glutes and hamstrings to lift your legs upward until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"5E610409-2E5F-5EBF-9CA9-5E784B0AB1F2","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"7E8043EA-8BE2-54F5-8962-7D30D8BC1E19","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('337973A7-EA28-5D42-B36E-85D1BA09D738'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"337973A7-EA28-5D42-B36E-85D1BA09D738","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever Reverse T-Bar Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and footplate position on the leverage machine.","Sit on the machine with your chest against the pad and your feet flat on the footplate.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and engage your core.","Pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"3979EC05-432A-5602-8383-2CC815F997DB","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"406215DF-2E0E-5006-AB88-FA97C4546A12","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('14A12B6F-7596-5BB6-A272-EC5EAF2C9698'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"14A12B6F-7596-5BB6-A272-EC5EAF2C9698","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Soleus","Ankle Stabilizers"],"name":"Lever Rotary Calf","notes":"","plannedSets":3,"proTips":["Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate.","Place your toes on the footplate, with your heels hanging off the edge.","Grasp the handles or the sides of the machine for stability.","Push through the balls of your feet, raising your heels as high as possible.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"DF46B1E3-A715-5396-9A12-68F22CFB1C01","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"56C52812-5E7A-5563-BEF9-06DD35390DF7","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0A8050FB-3373-5DB3-8FD5-EA0EB5DA7C82'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"0A8050FB-3373-5DB3-8FD5-EA0EB5DA7C82","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Soleus","Hamstrings"],"name":"Lever Seated Calf Press","notes":"","plannedSets":3,"proTips":["Adjust the seat of the machine so that your shoulders are aligned with the lever pad.","Place your toes on the lower portion of the platform and position your knees under the lever pad.","Grasp the handles on the sides of the seat for stability.","Press the lever pad down by extending your ankles, lifting your heels as high as possible.","Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"877EBB20-0686-5E4A-BCA6-FE043D16F306","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B5644FBE-5A7B-51ED-B0A6-5F6F078B98B5","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('14910068-9B46-5E90-A2C3-D0E40C5477D3'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"14910068-9B46-5E90-A2C3-D0E40C5477D3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Soleus","Ankle Stabilizers"],"name":"Lever Seated Calf Raise","notes":"","plannedSets":3,"proTips":["Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate.","Place your toes on the footplate with your heels hanging off the edge.","Grasp the handles or the sides of the seat for stability.","Push through the balls of your feet to raise your heels as high as possible.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"584555BB-D9A0-5222-B6B4-BE1AB7D72873","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"AA176CD3-67DE-5F1F-A6CF-41BDF1E8CE24","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('71678E5A-F547-5117-8512-45B233054C06'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Machine","hint":"","id":"71678E5A-F547-5117-8512-45B233054C06","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Lever Seated Crunch","notes":"","plannedSets":3,"proTips":["Sit on the leverage machine with your back against the pad and your feet flat on the floor.","Grasp the handles or place your hands on the side pads for support.","Engage your abs and slowly lean back, allowing the pad to move with you.","Once your upper body is at a 45-degree angle, contract your abs and crunch forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly release and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"7ED0B0D4-B1DF-5675-950C-063D2DF2E0B5","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"A66AC1D4-3BB1-5612-9EE3-2F1A50AD712D","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('56D4154F-A157-5926-9E52-75DEA46AD3BC'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Machine","hint":"","id":"56D4154F-A157-5926-9E52-75DEA46AD3BC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Lever Seated Crunch (Chest Pad)","notes":"","plannedSets":3,"proTips":["Adjust the seat height and chest pad position according to your comfort.","Sit on the machine with your back against the chest pad and your feet flat on the floor.","Grasp the handles or side bars for stability.","Engage your abs and slowly lean back, allowing the chest pad to move with you.","Pause for a moment at the maximum contraction, feeling the tension in your abs.","Slowly return to the starting position by contracting your abs and pulling yourself back up.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"9474F7FD-D750-59C4-AF74-E90DA8C9EF34","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"9E5EF8C0-FA1A-5BCF-8F12-12D74CA27550","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B0B3085B-7FB1-51EF-8F86-F5324869021D'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Machine","hint":"","id":"B0B3085B-7FB1-51EF-8F86-F5324869021D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Hip Flexors"],"name":"Lever Seated Crunch V. 2","notes":"","plannedSets":3,"proTips":["Sit on the leverage machine with your back against the pad and your feet secured under the footpads.","Place your hands on the handles or the sides of the seat for support.","Engage your abs and slowly crunch forward, bringing your chest towards your knees.","Pause for a moment at the top of the movement, squeezing your abs.","Slowly return to the starting position, allowing your back to round slightly.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"076B73E1-50C4-5049-AEB6-DE3F113DD991","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"50CEDCE3-BA5D-59B2-AFED-7A873F1AFACB","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('788A378E-2925-5D4C-A553-943D91E4EFF9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"788A378E-2925-5D4C-A553-943D91E4EFF9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Lever Seated Dip","notes":"","plannedSets":3,"proTips":["Adjust the seat height so that your feet are flat on the ground and your knees are at a 90-degree angle.","Grasp the handles of the leverage machine with your palms facing down and your arms fully extended.","Slowly lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"39DE4E71-FC6F-524A-9853-652DF57EE48E","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"99B26B0D-27E7-5E44-B291-8D261B9AE857","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D0206F28-6A4A-5476-9F50-2F12D040FEA8'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Machine","hint":"","id":"D0206F28-6A4A-5476-9F50-2F12D040FEA8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Trapezius"],"name":"Lever Seated Fly","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles with a pronated grip and keep your elbows slightly bent.","Exhale and push the handles forward, bringing them together in front of your chest.","Pause for a moment, squeezing your chest muscles.","Inhale and slowly return to the starting position, allowing your chest muscles to stretch.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"79CB9725-58B8-5D38-9704-C2B576A27C38","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"52768B6D-60F9-5AD0-81A8-1BAEEA96A3B5","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D0A8F913-C8C1-5C32-9FAE-53C3B6351F5F'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"D0A8F913-C8C1-5C32-9FAE-53C3B6351F5F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Lever Seated Good Morning","notes":"","plannedSets":3,"proTips":["Adjust the seat height so that your hips are slightly higher than your knees.","Sit on the machine with your back against the pad and your feet flat on the footrests.","Grasp the handles or the sides of the seat for stability.","Keeping your back straight, slowly lean forward from your hips until your upper body is parallel to the ground.","Pause for a moment, then slowly return to the starting position by pushing through your glutes and hamstrings.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"68997B0F-9B93-5481-9929-E8FEB7F7D466","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1A320386-51DE-50F8-93B0-F88E87446357","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('ACD78077-5BE1-5327-B19D-FAA7420EE891'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"ACD78077-5BE1-5327-B19D-FAA7420EE891","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abductors","Glutes","Hamstrings"],"name":"Lever Seated Hip Abduction","notes":"","plannedSets":3,"proTips":["Adjust the seat height so that your knees are at a 90-degree angle.","Sit on the machine with your back against the backrest and your feet on the footrests.","Place your hands on the side handles for stability.","Engage your abductors and slowly push your legs apart, away from the midline of your body.","Pause for a moment at the end of the movement, then slowly bring your legs back together to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"9CBAAB3E-575C-5779-AD4E-481200D03CB8","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"52A78CEF-AF15-5D97-9EA3-2746DA419767","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6B6888CA-6CA8-5711-94D5-B36127B04F21'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"6B6888CA-6CA8-5711-94D5-B36127B04F21","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Adductors","Hamstrings","Glutes"],"name":"Lever Seated Hip Adduction","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back against the backrest.","Place your feet on the footrests and grasp the handles for stability.","Engage your adductor muscles and slowly bring your legs together, squeezing your inner thighs.","Pause for a moment at the peak contraction, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6F78BFAB-331C-54A3-940B-6BB3118B64CF","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3F4AA215-5FAD-5E5B-BAE7-149C7F03466B","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1858A82A-EFA0-5603-8677-44B413C1EAD1'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"1858A82A-EFA0-5603-8677-44B413C1EAD1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Calves"],"name":"Lever Seated Leg Curl","notes":"","plannedSets":3,"proTips":["Adjust the machine to fit your body and sit on it with your back against the backrest.","Place your lower legs under the padded lever, just above your ankles.","Grasp the handles on the sides of the machine for support.","Keeping your upper legs stationary, exhale and curl your legs up as far as possible.","Hold the contracted position for a brief pause as you squeeze your hamstrings.","Inhale and slowly lower the lever back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D11E53DA-E189-5829-892C-529F4EE8BA88","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"18E22469-678D-58A3-81A5-EB57039E95E0","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1713FE1C-8D30-5029-8213-C057A0628C61'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Machine","hint":"","id":"1713FE1C-8D30-5029-8213-C057A0628C61","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Lever Seated Leg Raise Crunch","notes":"","plannedSets":3,"proTips":["Sit on the leverage machine with your back against the backrest and your feet on the footrests.","Grasp the handles or sidebars for stability.","Engage your abs and slowly raise your legs up towards your chest, curling your torso forward at the same time.","Pause for a moment at the top, then slowly lower your legs and torso back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"2069FFF2-2D93-5A29-986D-CBB2EDF489B7","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"99323CBA-A5E8-5491-9829-BE434B12CB00","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0D03BF74-F08E-55B3-8898-B9DD0685B443'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Machine","hint":"","id":"0D03BF74-F08E-55B3-8898-B9DD0685B443","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Lever Seated Reverse Fly","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.","Grasp the handles with an overhand grip and keep your arms slightly bent.","Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body.","Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6DF00458-7075-589D-B18D-0C8BADD87394","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"F54F2372-3B88-5603-B2B0-CEFAAC98973F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('92393BE3-B8A1-5F4C-8E78-2561331AC9EF'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Machine","hint":"","id":"92393BE3-B8A1-5F4C-8E78-2561331AC9EF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Lever Seated Reverse Fly (Parallel Grip)","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.","Grasp the handles with a parallel grip, palms facing each other, and keep your arms slightly bent.","Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body.","Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"302D424C-A358-5DF6-A87A-9E4B24728ACB","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"A2569F4B-A594-53E5-8AB9-4EFE59A42F30","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6EF87F5F-554D-5A85-9CD2-21764F501199'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"6EF87F5F-554D-5A85-9CD2-21764F501199","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever Seated Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and footrests to a comfortable position.","Sit on the machine with your chest against the pad and your feet on the footrests.","Grasp the handles with an overhand grip, shoulder-width apart.","Keep your back straight and your core engaged.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement.","Slowly release the handles and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D7507DFC-57F5-57F8-B4C8-10AC0FF6C6E9","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"937D8772-B834-5FAD-B3FF-6119B07EAD3E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5EB9A887-1D43-5D3D-9712-2D2D18A6A0E4'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Machine","hint":"","id":"5EB9A887-1D43-5D3D-9712-2D2D18A6A0E4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Quadriceps","Hamstrings","Glutes"],"name":"Lever Seated Squat Calf Raise On Leg Press Machine","notes":"","plannedSets":3,"proTips":["Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the footplate.","Sit on the machine with your back against the backrest and your feet flat on the footplate, shoulder-width apart.","Place your toes and the balls of your feet on the footplate, keeping your heels off the edge.","Release the safety handles and push the footplate away from you by extending your knees.","Once your knees are fully extended, slowly lower your heels by flexing your calves.","Pause for a moment at the bottom, then push the footplate back up by extending your calves.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"BBD6B16F-BCDA-5336-82C4-B467028E0B11","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"36B483AB-D780-5F5B-B8E5-3BF70398478A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('43E6328C-51FD-5091-8BE4-AE102B70FD6A'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Machine","hint":"","id":"43E6328C-51FD-5091-8BE4-AE102B70FD6A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Chest"],"name":"Lever Shoulder Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back against the backrest.","Grasp the handles with an overhand grip and position your hands at shoulder level.","Push the handles upward until your arms are fully extended, but do not lock your elbows.","Pause for a moment at the top, then slowly lower the handles back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"7581AF6A-6725-5C72-BDEC-19B01CF360C1","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"288CD242-0FC6-5A80-ADB7-E24E9DC35749","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('78092C21-03BF-58C7-BF88-397E08FCC081'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Machine","hint":"","id":"78092C21-03BF-58C7-BF88-397E08FCC081","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Chest"],"name":"Lever Shoulder Press V. 2","notes":"","plannedSets":3,"proTips":["Adjust the seat height and backrest of the leverage machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet flat on the floor.","Grasp the handles of the machine with an overhand grip, slightly wider than shoulder-width apart.","Push the handles upward and forward until your arms are fully extended, but not locked.","Pause for a moment at the top, then slowly lower the handles back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B546F362-1B1A-54A8-927C-DD5FA38C3D94","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"96AF7AD2-1D19-578F-A9C5-9552DFC46AFE","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
