  ('21A6744A-A52F-5FE0-94A5-12F162E0C23F'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"21A6744A-A52F-5FE0-94A5-12F162E0C23F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders"],"name":"Lever Shrug","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the leverage machine with your back against the pad.","Grasp the handles with an overhand grip and keep your arms straight.","Keeping your back straight, lift your shoulders up towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"5570FB81-3328-54B1-9828-80E911C0F032","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"411520C5-674C-523A-936C-F2E8BCB6389A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7F3889A9-1509-5B47-9AF5-418B05D7ADE6'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Machine","hint":"","id":"7F3889A9-1509-5B47-9AF5-418B05D7ADE6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Soleus","Ankle Stabilizers"],"name":"Lever Standing Calf Raise","notes":"","plannedSets":3,"proTips":["Adjust the machine to your height and stand with your feet shoulder-width apart.","Place your shoulders under the pads and hold onto the handles for stability.","Raise your heels as high as possible by extending your ankles.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"C92D44E2-9EA5-50D1-B8AA-CAF97199559B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C3CAB96D-8F21-5413-8F13-C2A2F79065C6","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2627FB84-040C-51A9-AB9E-590AD6FA4FA9'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Machine","hint":"","id":"2627FB84-040C-51A9-AB9E-590AD6FA4FA9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Lever Standing Chest Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your feet flat on the ground.","Grasp the handles with an overhand grip and position your hands at chest level.","Push the handles forward until your arms are fully extended, keeping your elbows slightly bent.","Pause for a moment, then slowly bring the handles back towards your chest, maintaining control throughout the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"675BC36C-7C58-522F-A242-EF40F2F699A6","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"6F42C0BB-A9A7-57E2-BE25-B661E19053D4","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5DE4D349-F84A-5C95-A35B-6DCB431E67E7'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"5DE4D349-F84A-5C95-A35B-6DCB431E67E7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever T Bar Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and footplate position to ensure proper alignment.","Sit on the machine with your chest against the pad and your feet flat on the footplate.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and engage your core.","Pull the handles towards your torso, squeezing your shoulder blades together.","Pause for a moment at the peak contraction, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D681AFC8-4E93-5946-A777-0C51847FF400","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"955E84AB-58CF-56AC-8ABD-252A9A4FAD2C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A7DF6B13-9C58-5ED0-ADA6-EB7211CC0305'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"A7DF6B13-9C58-5ED0-ADA6-EB7211CC0305","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever T-Bar Reverse Grip Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and engage your core.","Pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"2A4EABDF-A5B0-56EB-AD44-B04B4CF66612","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4656542E-FF1D-5FA2-9CB9-213774943022","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('941CDF58-21AB-551D-A939-D75480B44C29'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"941CDF58-21AB-551D-A939-D75480B44C29","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Lever Triceps Extension","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles with an overhand grip and fully extend your arms in front of you.","Keeping your upper arms stationary, slowly lower the handles towards your forehead by bending your elbows.","Pause for a moment at the bottom, then push the handles back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"E1ACD4A1-4920-5322-AE13-12A9E73E1DD0","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"91138F43-5503-5C4C-9745-740C7095D281","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3FABA1EE-594A-5CCD-8275-1ADDDC022D7B'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"3FABA1EE-594A-5CCD-8275-1ADDDC022D7B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Lever Unilateral Row","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself facing the machine.","Grasp the handles with an overhand grip and keep your back straight.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"0A5A3913-48ED-5D47-B8B8-DA7BC9A0ADB7","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"CFFF195E-44DF-54CA-A491-2D1AA22EF895","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C2CD6B22-035A-590C-9D98-382C1452F09D'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Rope","hint":"","id":"C2CD6B22-035A-590C-9D98-382C1452F09D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Shoulders","Biceps","Forearms"],"name":"London Bridge","notes":"","plannedSets":3,"proTips":["Attach the rope to a high anchor point.","Stand facing away from the anchor point with your feet shoulder-width apart.","Grasp the rope with an overhand grip, palms facing down.","Lean forward slightly, keeping your back straight and core engaged.","Pull the rope towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"29168002-B52F-5893-BE82-7E00D8854D13","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CD1A458B-DB7A-5B6F-8B88-E02BDCB63AE1'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CD1A458B-DB7A-5B6F-8B88-E02BDCB63AE1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Core"],"name":"Low Glute Bridge On Floor","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your arms by your sides, palms facing down.","Engage your glutes and core, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E6A47D55-2C89-5E03-972F-CA9893871F9A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2A21CE2D-B0FF-59C2-AE82-F5F5A0D39379'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2A21CE2D-B0FF-59C2-AE82-F5F5A0D39379","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Lower Back Curl","notes":"","plannedSets":3,"proTips":["Lie flat on your stomach with your legs extended and your arms by your sides.","Engage your glutes and hamstrings, and slowly lift your upper body off the ground, curling your back upwards.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3F89F8CA-17F6-5125-B3E2-47E4AD045404","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('55B493CA-C5E6-57DA-9AAD-1C5DC5DE4C39'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"55B493CA-C5E6-57DA-9AAD-1C5DC5DE4C39","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Lunge With Jump","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart.","Take a step forward with your right foot, lowering your body into a lunge position.","Push off with your right foot and jump into the air, switching the position of your feet mid-air.","Land softly with your left foot forward and immediately lower your body into a lunge position.","Continue alternating between lunges and jumps for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0645CFBD-64D8-5F27-BAAF-53BAD31F9FFB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6283379D-9F52-5BEB-AA28-AAF8E4C4F167'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6283379D-9F52-5BEB-AA28-AAF8E4C4F167","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Quadriceps","Glutes","Hamstrings"],"name":"Lunge With Twist","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart.","Take a step forward with your right foot, lowering your body into a lunge position.","As you lunge, twist your torso to the right, bringing your left elbow towards your right knee.","Pause for a moment, then return to the starting position.","Repeat on the other side, stepping forward with your left foot and twisting your torso to the left.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7A9560B3-33E6-5298-B657-E76E32B4522F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now())
